content:
resource "aws_bedrock_guardrail" "this" {
  name                      = var.name
  blocked_input_messaging   = var.blocked_input_messaging
  blocked_outputs_messaging = var.blocked_outputs_messaging
  description               = var.description
  region                    = var.region
  kms_key_arn               = var.kms_key_arn
  tags                      = var.tags

  dynamic "content_policy_config" {
    for_each = var.content_policy_config != null ? [var.content_policy_config] : []
    content {
      dynamic "filters_config" {
        for_each = content_policy_config.value.filters_config != null ? content_policy_config.value.filters_config : []
        content {
          input_strength  = filters_config.value.input_strength
          output_strength = filters_config.value.output_strength
          type            = filters_config.value.type
        }
      }

      dynamic "tier_config" {
        for_each = content_policy_config.value.tier_config != null ? [content_policy_config.value.tier_config] : []
        content {
          tier_name = tier_config.value.tier_name
        }
      }
    }
  }

  dynamic "contextual_grounding_policy_config" {
    for_each = var.contextual_grounding_policy_config != null ? [var.contextual_grounding_policy_config] : []
    content {
      dynamic "filters_config" {
        for_each = contextual_grounding_policy_config.value.filters_config != null ? contextual_grounding_policy_config.value.filters_config : []
        content {
          threshold = filters_config.value.threshold
          type      = filters_config.value.type
        }
      }
    }
  }

  dynamic "cross_region_config" {
    for_each = var.cross_region_config != null ? [var.cross_region_config] : []
    content {
      guardrail_profile_identifier = cross_region_config.value.guardrail_profile_identifier
    }
  }

  dynamic "sensitive_information_policy_config" {
    for_each = var.sensitive_information_policy_config != null ? [var.sensitive_information_policy_config] : []
    content {
      dynamic "pii_entities_config" {
        for_each = sensitive_information_policy_config.value.pii_entities_config != null ? sensitive_information_policy_config.value.pii_entities_config : []
        content {
          action         = pii_entities_config.value.action
          input_action   = pii_entities_config.value.input_action
          output_action  = pii_entities_config.value.output_action
          input_enabled  = pii_entities_config.value.input_enabled
          output_enabled = pii_entities_config.value.output_enabled
          type           = pii_entities_config.value.type
        }
      }

      dynamic "regexes_config" {
        for_each = sensitive_information_policy_config.value.regexes_config != null ? sensitive_information_policy_config.value.regexes_config : []
        content {
          action         = regexes_config.value.action
          input_action   = regexes_config.value.input_action
          output_action  = regexes_config.value.output_action
          input_enabled  = regexes_config.value.input_enabled
          output_enabled = regexes_config.value.output_enabled
          description    = regexes_config.value.description
          name           = regexes_config.value.name
          pattern        = regexes_config.value.pattern
        }
      }
    }
  }

  dynamic "topic_policy_config" {
    for_each = var.topic_policy_config != null ? [var.topic_policy_config] : []
    content {
      dynamic "topics_config" {
        for_each = topic_policy_config.value.topics_config != null ? topic_policy_config.value.topics_config : []
        content {
          name       = topics_config.value.name
          examples   = topics_config.value.examples
          type       = topics_config.value.type
          definition = topics_config.value.definition
        }
      }

      dynamic "tier_config" {
        for_each = topic_policy_config.value.tier_config != null ? [topic_policy_config.value.tier_config] : []
        content {
          tier_name = tier_config.value.tier_name
        }
      }
    }
  }

  dynamic "word_policy_config" {
    for_each = var.word_policy_config != null ? [var.word_policy_config] : []
    content {
      dynamic "managed_word_lists_config" {
        for_each = word_policy_config.value.managed_word_lists_config != null ? word_policy_config.value.managed_word_lists_config : []
        content {
          type           = managed_word_lists_config.value.type
          input_action   = managed_word_lists_config.value.input_action
          input_enabled  = managed_word_lists_config.value.input_enabled
          output_action  = managed_word_lists_config.value.output_action
          output_enabled = managed_word_lists_config.value.output_enabled
        }
      }

      dynamic "words_config" {
        for_each = word_policy_config.value.words_config != null ? word_policy_config.value.words_config : []
        content {
          text           = words_config.value.text
          input_action   = words_config.value.input_action
          input_enabled  = words_config.value.input_enabled
          output_action  = words_config.value.output_action
          output_enabled = words_config.value.output_enabled
        }
      }
    }
  }
}

resource "aws_efs_access_point" "this" {
  file_system_id = var.file_system_id

  dynamic "posix_user" {
    for_each = var.posix_user != null ? [var.posix_user] : []
    content {
      gid            = posix_user.value.gid
      secondary_gids = posix_user.value.secondary_gids
      uid            = posix_user.value.uid
    }
  }

  dynamic "root_directory" {
    for_each = var.root_directory != null ? [var.root_directory] : []
    content {
      path = root_directory.value.path

      dynamic "creation_info" {
        for_each = root_directory.value.creation_info != null ? [root_directory.value.creation_info] : []
        content {
          owner_gid   = creation_info.value.owner_gid
          owner_uid   = creation_info.value.owner_uid
          permissions = creation_info.value.permissions
        }
      }
    }
  }

  tags = var.tags
}

variable "aiven_token" {
  description = "Aiven token"
  type        = string
}

variable "aiven_project" {
  description = "Aiven project name"
  type        = string
}

terraform {
  required_providers {
    azurecaf = {
      source  = "aztfmod/azurecaf"
      version = "1.2.26"
    }
    azuread = {
      source  = "hashicorp/azuread"
      version = "2.41.0"
    }
  }
}

resource "azurecaf_name" "container_registry" {
  name          = var.application_name
  resource_type = "azurerm_container_registry"
  suffixes      = [var.environment]
}

resource "azurerm_container_registry" "container-registry" {
  name                = azurecaf_name.container_registry.result
  resource_group_name = var.resource_group
  location            = var.location
  admin_enabled       = true
  sku                 = "Basic"

  tags = {
    "environment"      = var.environment
    "application-name" = var.application_name
  }
}

resource "azurecaf_name" "log_analytics_workspace" {
  name          = var.application_name
  resource_type = "azurerm_log_analytics_workspace"
  suffixes      = [var.environment]
}

resource "azurerm_log_analytics_workspace" "application" {
  name                = azurecaf_name.log_analytics_workspace.result
  resource_group_name = var.resource_group
  location            = var.location
  sku                 = "PerGB2018"
  retention_in_days   = 30
}

resource "azurecaf_name" "application-environment" {
  name          = var.application_name
  resource_type = "azurerm_container_app_environment"
  suffixes      = [var.environment]
}

resource "azurerm_container_app_environment" "application" {
  name                       = azurecaf_name.application-environment.result
  resource_group_name        = var.resource_group
  location                   = var.location
  log_analytics_workspace_id = azurerm_log_analytics_workspace.application.id
}

resource "azurecaf_name" "application" {
  name          = var.application_name
  resource_type = "azurerm_container_app"
  suffixes      = [var.environment]
}

resource "azurerm_container_app" "application" {
  name                         = azurecaf_name.application.result
  container_app_environment_id = azurerm_container_app_environment.application.id
  resource_group_name          = var.resource_group
  revision_mode                = "Single"

  lifecycle {
    ignore_changes = [
      template.0.container["image"]
    ]
  }

  identity {
    type = "SystemAssigned"
  }

  secret {
    name  = "registry-credentials"
    value = azurerm_container_registry.container-registry.admin_password
  }

  registry {
    server               = azurerm_container_registry.container-registry.login_server
    username             = azurerm_container_registry.container-registry.admin_username
    password_secret_name = "registry-credentials"
  }

  ingress {
    external_enabled = true
    target_port      = 8080
    traffic_weight {
      percentage = 100
      latest_revision = true
    }
  }

  template {
    container {
      name   = azurecaf_name.application.result
      image  = "ghcr.io/microsoft/nubesgen/nubesgen-native:main"
      cpu    = 0.25
      memory = "0.5Gi"
      env {
        name  = "SPRING_PROFILES_ACTIVE"
        value = "prod,azure"
      }
      env {
        name  = "SPRING_DATASOURCE_URL"
        value = "jdbc:postgresql://${var.database_url}"
      }
      env {
        name  = "AZURE_KEYVAULT_ENABLED"
        value = "true"
      }
      env {
        name  = "AZURE_KEYVAULT_URI"
        value = var.vault_uri
      }
    }
    min_replicas = 1
  }
}

data "azuread_service_principal" "application" {
  display_name = azurerm_container_app.application.name
  depends_on = [
    azurerm_container_app.application
  ]
}

data "azurerm_client_config" "current" {}

resource "azurerm_key_vault_access_policy" "application" {
  key_vault_id = var.vault_id
  tenant_id    = data.azurerm_client_config.current.tenant_id
  object_id    = data.azuread_service_principal.application.id

  secret_permissions = [
    "Get",
    "List"
  ]
}

locals {
  enabled   = module.this.enabled
  partition = join("", data.aws_partition.current[*].partition)
}

data "aws_partition" "current" {
  count = local.enabled ? 1 : 0
}

module "cert_manager" {
  source  = "cloudposse/helm-release/aws"
  version = "0.10.0"

  name            = "" # avoids hitting length restrictions on IAM Role names
  chart           = var.cert_manager_chart
  repository      = var.cert_manager_repository
  description     = var.cert_manager_description
  chart_version   = var.cert_manager_chart_version
  wait            = var.wait || var.letsencrypt_enabled || var.cert_manager_issuer_selfsigned_enabled
  atomic          = var.atomic
  cleanup_on_fail = var.cleanup_on_fail
  timeout         = var.timeout

  create_namespace_with_kubernetes = var.create_namespace
  kubernetes_namespace             = var.kubernetes_namespace
  kubernetes_namespace_labels      = merge(module.this.tags, { name = var.kubernetes_namespace })

  # Only install IAM role if letsencrypt_enabled is true
  iam_role_enabled            = var.letsencrypt_enabled
  eks_cluster_oidc_issuer_url = replace(module.eks.outputs.eks_cluster_identity_oidc_issuer, "https://", "")

  service_account_name                        = module.this.name
  service_account_namespace                   = var.kubernetes_namespace
  service_account_role_arn_annotation_enabled = var.letsencrypt_enabled

  iam_policy_statements = {
    GrantGetChange = {
      effect = "Allow"
      actions = [
        "route53:GetChange"
      ]
      resources = [
        "arn:${local.partition}:route53:::change/*"
      ]
      conditions = []
    }
    GrantListHostedZonesListResourceRecordSets = {
      effect = "Allow"
      actions = [
        "route53:ListHostedZonesByName"
      ]
      resources  = ["*"]
      conditions = []
    },
    GrantChangeResourceRecordSets = {
      effect = "Allow"
      actions = [
        "route53:ChangeResourceRecordSets",
        "route53:ListResourceRecordSets",
      ]
      resources = [
        for zone_id in concat(
          [],
          [for value in module.dns_gbl_delegated.outputs.zones : value.zone_id]
        ) :
        "arn:${local.partition}:route53:::hostedzone/${zone_id}"
      ]
      conditions : []
    }
  }

  values = compact([
    # hardcoded values
    file("${path.module}/resources/cert-manager-values.yaml"),
    # standard k8s object settings
    yamlencode({
      fullnameOverride = module.this.name,
      serviceAccount = {
        name = module.this.name
      },
      resources = var.cert_manager_resources
      rbac = {
        create = var.cart_manager_rbac_enabled
      }
    }),
    # cert-manager-specific values
    var.letsencrypt_enabled ? yamlencode({
      ingressShim = {
        defaultIssuerName                = "ClusterIssuer"
        ingress_shim_default_issuer_name = "letsencrypt-staging"
      },
    }) : "",
    var.cert_manager_metrics_enabled ? yamlencode({
      prometheus = {
        enabled = var.cert_manager_metrics_enabled
        servicemonitor = {
          enabled = var.cert_manager_metrics_enabled
        }
      }
    }) : "",
    # additional values
    yamlencode(var.cert_manager_values)
  ])

  context = module.this.context
}

module "cert_manager_issuer" {
  source  = "cloudposse/helm-release/aws"
  version = "0.10.0"

  # Only install the issuer if either letsencrypt_installed or selfsigned_installed is true
  enabled = local.enabled && (var.letsencrypt_enabled || var.cert_manager_issuer_selfsigned_enabled)

  name                 = "${module.this.name}-issuer"
  chart                = var.cert_manager_issuer_chart
  repository           = var.cert_manager_issuer_repository
  description          = var.cert_manager_issuer_description
  chart_version        = var.cert_manager_issuer_chart_version
  kubernetes_namespace = var.kubernetes_namespace
  create_namespace     = false
  wait                 = var.wait
  atomic               = var.atomic
  cleanup_on_fail      = var.cleanup_on_fail
  timeout              = var.timeout

  # IAM role will be created by the cert-manager module above, if needed. Do not create a duplicate here.
  iam_role_enabled            = false
  eks_cluster_oidc_issuer_url = replace(module.eks.outputs.eks_cluster_identity_oidc_issuer, "https://", "")

  # NOTE: Use with the local chart
  values = compact([
    yamlencode({
      letsencrypt_installed  = var.letsencrypt_enabled
      selfsigned_installed   = var.cert_manager_issuer_selfsigned_enabled
      account                = join("-", compact([module.this.tenant, module.this.stage]))
      support_email_template = var.cert_manager_issuer_support_email_template
      stage                  = var.stage
      dns_region             = var.region
    }),
    yamlencode(var.cert_manager_issuer_values)
  ])

  context = module.this.context

  depends_on = [
    # CRDs from cert-manager need to be installed first
    module.cert_manager,
  ]
}

#---------------------------------------------------
# Heroku addon
#---------------------------------------------------
variable "enable_addon" {
  description = "Enable Heroku addon usage"
  default     = false
}

variable "addon_name" {
  description = "(Optional) Globally unique name of the add-on."
  default     = null
}

variable "addon_app" {
  description = "(Required) The Heroku app to add to."
  default     = null
}

variable "addon_plan" {
  description = "(Required) The addon to add."
  default     = null
}

variable "addon_config" {
  description = "(Optional) Optional plan configuration."
  default     = null
}

#---------------------------------------------------
# Heroku addon attachment
#---------------------------------------------------
variable "enable_addon_attachment" {
  description = "Enable Heroku addon attachment usage"
  default     = false
}

variable "addon_attachment_name" {
  description = "(Optional) A friendly name for the Heroku Addon Attachment."
  default     = null
}

variable "addon_attachment_app_id" {
  description = "(Required) The ID of the Heroku App to attach to."
  default     = null
}

variable "addon_attachment_addon_id" {
  description = "(Required) The ID of the existing Heroku Addon to attach."
  default     = ""
}

variable "addon_attachment_namespace" {
  description = "(Optional) The namespace value for the Heroku Addon Attachment. This can be used to configure the behaviour of the attachment. See Heroku Platform API Reference"
  default     = null
}

resource "aiven_clickhouse_role" "example_role" {
  project      = data.aiven_project.example_project.project
  service_name = aiven_clickhouse.example_clickhouse.service_name
  role         = "example-role"
}

# Grant privileges to the example role.
resource "aiven_clickhouse_grant" "role_privileges" {
  project      = data.aiven_project.example_project.project
  service_name = aiven_clickhouse.example_clickhouse.service_name
  role         = aiven_clickhouse_role.example_role.role

  privilege_grant {
    privilege = "INSERT"
    database  = aiven_clickhouse_database.example_db.name
    table     = "example-table"
  }

  privilege_grant {
    privilege = "SELECT"
    database  = aiven_clickhouse_database.example_db.name
  }

  # Global privileges
  privilege_grant {
    privilege = "CREATE TEMPORARY TABLE"
    database  = "*"
  }

  privilege_grant {
    privilege = "SYSTEM DROP CACHE"
    database  = "*"
  }
}

# Grant the role to the user.
resource "aiven_clickhouse_user" "example_user" {
  project      = data.aiven_project.example_project.project
  service_name = aiven_clickhouse.example_clickhouse.service_name
  username     = "example-user"
}

resource "aiven_clickhouse_grant" "user_role_assignment" {
  project      = data.aiven_project.example_project.project
  service_name = aiven_clickhouse.example_clickhouse.service_name
  user         = aiven_clickhouse_user.example_user.username

  role_grant {
    role = aiven_clickhouse_role.example_role.role
  }
}

terraform {
  required_providers {
    coder = {
      source  = "coder/coder"
      version = "~> 0.6.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.12.1"
    }
  }
}

variable "use_kubeconfig" {
  type        = bool
  sensitive   = true
  description = <<-EOF
  Use host kubeconfig? (true/false)

  Set this to false if the Coder host is itself running as a Pod on the same
  Kubernetes cluster as you are deploying workspaces to.

  Set this to true if the Coder host is running outside the Kubernetes cluster
  for workspaces.  A valid "~/.kube/config" must be present on the Coder host. This
  is likely not your local machine unless you are using `coder server --dev.`

  EOF
}

variable "workspaces_namespace" {
  description = <<-EOF
  Kubernetes namespace to deploy the workspace into

  EOF
  default     = ""

}

provider "kubernetes" {
  # Authenticate via ~/.kube/config or a Coder-specific ServiceAccount, depending on admin preferences
  config_path = var.use_kubeconfig == true ? "~/.kube/config" : null
}

data "coder_workspace" "me" {}

variable "cpu" {
  description = "CPU (__ cores)"
  default     = 2
  validation {
    condition = contains([
      "2",
      "4",
      "6",
      "8",
      "10"
    ], var.cpu)
    error_message = "Invalid cpu!"
}
}

variable "memory" {
  description = "Memory (__ GB)"
  default     = 4
  validation {
    condition = contains([
      "2",
      "4",
      "6",
      "8",
      "10",
      "12"
    ], var.memory)
    error_message = "Invalid memory!"
}
}

variable "disk_size" {
  description = "Disk size (__ GB)"
  default     = 10
}

variable "dotfiles_uri" {
  description = <<-EOF
  Dotfiles repo URI (optional)

  see https://dotfiles.github.io
  EOF
  default     = "git@github.com:sharkymark/dotfiles.git"
}

resource "coder_agent" "dev" {
  os             = "linux"
  arch           = "amd64"
  dir            = "/home/coder"
  startup_script = <<EOF
    #!/bin/sh

    # Start code-server
    code-server --auth none --port 13337 &

    # Configure and run JetBrains IDE

    # Assumes you have
    # GoLand (/opt/goland), and pip3 installed in
    # your image and the "coder" user has filesystem
    # permissions for "/opt/*"
    pip3 install projector-installer --user
    /home/coder/.local/bin/projector --accept-license

    /home/coder/.local/bin/projector config add goland /opt/goland --force --use-separate-config --port 9001  --hostname localhost
    /home/coder/.local/bin/projector run goland &

    # clone 3 Go repos
    mkdir -p ~/.ssh
    ssh-keyscan -t ed25519 github.com >> ~/.ssh/known_hosts
    git clone --progress git@github.com:sharkymark/chi_helloworld.git &
    git clone --progress git@github.com:sharkymark/commissions.git &
    git clone --progress git@github.com:coder/coder.git &

    ${var.dotfiles_uri != "" ? "coder dotfiles -y ${var.dotfiles_uri}" : ""}
  EOF
}

# code-server
resource "coder_app" "code-server" {
  agent_id = coder_agent.dev.id
  slug          = "code-server"
  display_name  = "VS Code"
  icon     = "/icon/code.svg"
  url      = "http://localhost:13337"
  subdomain = false
  share     = "owner"

  healthcheck {
    url       = "http://localhost:13337/healthz"
    interval  = 3
    threshold = 10
  }
}

resource "coder_app" "goland" {
  agent_id = coder_agent.dev.id
  slug          = "goland"
  display_name  = "GoLand"
  icon     = "/icon/goland.svg"
  url      = "http://localhost:9001"
  subdomain = false
  share     = "owner"

  healthcheck {
    url       = "http://localhost:9001/healthz"
    interval  = 3
    threshold = 10
  }
}

resource "kubernetes_pod" "main" {
  count = data.coder_workspace.me.start_count
  depends_on = [
    kubernetes_persistent_volume_claim.home-directory
  ]
  metadata {
    name      = "coder-${data.coder_workspace.me.owner}-${data.coder_workspace.me.name}"
    namespace = var.workspaces_namespace
  }
  spec {
    security_context {
      run_as_user = 1000
      fs_group    = 1000
    }
    container {
      name    = "dev"
      image   = "docker.io/marktmilligan/goland:latest"
      image_pull_policy = "Always"
      command = ["sh", "-c", coder_agent.dev.init_script]
      security_context {
        run_as_user = "1000"
      }
      env {
        name  = "CODER_AGENT_TOKEN"
        value = coder_agent.dev.token
      }
      resources {
        requests = {
          cpu    = "500m"
          memory = "500Mi"
        }
        limits = {
          cpu    = "${var.cpu}"
          memory = "${var.memory}G"
        }
      }
      volume_mount {
        mount_path = "/home/coder"
        name       = "home-directory"
      }
    }
    volume {
      name = "home-directory"
      persistent_volume_claim {
        claim_name = kubernetes_persistent_volume_claim.home-directory.metadata.0.name
      }
    }
  }
}

resource "kubernetes_persistent_volume_claim" "home-directory" {
  metadata {
    name      = "coder-pvc-${data.coder_workspace.me.owner}-${data.coder_workspace.me.name}"
    namespace = var.workspaces_namespace
  }
  spec {
    access_modes = ["ReadWriteOnce"]
    resources {
      requests = {
        storage = "${var.disk_size}Gi"
      }
    }
  }
}

resource "coder_metadata" "workspace_info" {
  count       = data.coder_workspace.me.start_count
  resource_id = kubernetes_pod.main[0].id
  item {
    key   = "CPU"
    value = "${kubernetes_pod.main[0].spec[0].container[0].resources[0].limits.cpu} cores"
  }
  item {
    key   = "memory"
    value = "${var.memory}GB"
  }
  item {
    key   = "image"
    value = "${kubernetes_pod.main[0].spec[0].container[0].image}"
  }
  item {
    key   = "disk"
    value = "${var.disk_size}GiB"
  }
  item {
    key   = "volume"
    value = kubernetes_pod.main[0].spec[0].container[0].volume_mount[0].mount_path
  }
}

terraform {
  required_version = "~> 1.6"
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.105"
    }
    azapi = {
      source  = "Azure/azapi"
      version = "~> 1.13, != 1.13.0"
    }
  }
}

provider "azurerm" {
  features {}
  alias                      = "AVS-to-ANFdatastore-NewVnet"
  partner_id                 = "938cd838-e22a-47da-8a6f-bdda923e3edb"
  skip_provider_registration = "true"
}

provider "azapi" {
  skip_provider_registration = "true"
  enable_hcl_output_for_data_source = true
}

resource "azurerm_resource_group" "deploymentRG" {
  provider = azurerm.AVS-to-ANFdatastore-NewVnet
  name     = var.DeploymentResourceGroupName
  location = var.Location
}

resource "azurerm_virtual_network" "vnetGatewayVnet" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.VNetName
  location            = azurerm_resource_group.deploymentRG.location
  resource_group_name = azurerm_resource_group.deploymentRG.name
  address_space       = var.VNetAddressSpaceCIDR
}

resource "azurerm_subnet" "gatewaySubnet" {
  provider             = azurerm.AVS-to-ANFdatastore-NewVnet
  name                 = "GatewaySubnet"
  resource_group_name  = azurerm_resource_group.deploymentRG.name
  virtual_network_name = azurerm_virtual_network.vnetGatewayVnet.name
  address_prefixes     = var.VNetGatewaySubnetCIDR
}

resource "azurerm_subnet" "ANFDelegatedSubnet" {
  provider             = azurerm.AVS-to-ANFdatastore-NewVnet
  name                 = "ANFDelegatedSubnet"
  resource_group_name  = azurerm_resource_group.deploymentRG.name
  virtual_network_name = azurerm_virtual_network.vnetGatewayVnet.name
  address_prefixes     = var.VNetANFDelegatedSubnetCIDR
  delegation {
    name = "microsoftnetapp"
    service_delegation {
      name = "Microsoft.Netapp/volumes"
    }
  }
}

resource "azurerm_public_ip" "gatewayIP" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = "${var.GatewayName}-PIP"
  resource_group_name = azurerm_resource_group.deploymentRG.name
  location            = azurerm_resource_group.deploymentRG.location
  allocation_method   = "Static"
  sku                 = "Standard"
  sku_tier            = "Regional"
  zones               = ["1","2","3"]

}

resource "azurerm_virtual_network_gateway" "ERGateway" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.GatewayName
  location            = azurerm_resource_group.deploymentRG.location
  resource_group_name = azurerm_resource_group.deploymentRG.name

  type = "ExpressRoute"
  sku  = var.GatewaySku

  ip_configuration {
    name                          = "vnetGatewayConfig"
    public_ip_address_id          = azurerm_public_ip.gatewayIP.id
    private_ip_address_allocation = "Dynamic"
    subnet_id                     = azurerm_subnet.gatewaySubnet.id
  }
}

#assumes the same subscription (need to reference different provider blocks if a separate sub is required.
data "azurerm_vmware_private_cloud" "existing" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.PrivateCloudName
  resource_group_name = var.PrivateCloudResourceGroup
}

#check this is the proper way to name the authorization
resource "azurerm_vmware_express_route_authorization" "thisVnet" {
  provider         = azurerm.AVS-to-ANFdatastore-NewVnet
  name             = azurerm_virtual_network.vnetGatewayVnet.name
  private_cloud_id = data.azurerm_vmware_private_cloud.existing.id
}

resource "azurerm_virtual_network_gateway_connection" "expressRoute" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.PrivateCloudName
  location            = azurerm_resource_group.deploymentRG.location
  resource_group_name = azurerm_resource_group.deploymentRG.name

  type                       = "ExpressRoute"
  virtual_network_gateway_id = azurerm_virtual_network_gateway.ERGateway.id
  express_route_circuit_id   = data.azurerm_vmware_private_cloud.existing.circuit[0].express_route_id

  authorization_key            = azurerm_vmware_express_route_authorization.thisVnet.express_route_authorization_key
  routing_weight               = 0
  express_route_gateway_bypass = true
}

resource "azurerm_netapp_account" "avs_anf_account" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.netappAccountName
  location            = azurerm_resource_group.deploymentRG.location
  resource_group_name = azurerm_resource_group.deploymentRG.name
}

resource "azurerm_netapp_pool" "avs_anf_pool" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.netappCapacityPoolName
  location            = azurerm_resource_group.deploymentRG.location
  resource_group_name = azurerm_resource_group.deploymentRG.name
  account_name        = azurerm_netapp_account.avs_anf_account.name
  service_level       = var.netappCapacityPoolServiceLevel
  size_in_tb          = var.netappCapacityPoolSize
}

resource "azurerm_netapp_volume" "anf_volume" {
  name                            = var.netappVolumeName
  location                        = azurerm_resource_group.deploymentRG.location
  resource_group_name             = azurerm_resource_group.deploymentRG.name
  account_name                    = azurerm_netapp_account.avs_anf_account.name
  pool_name                       = azurerm_netapp_pool.avs_anf_pool.name
  volume_path                     = var.netappVolumeName
  service_level                   = "Standard"
  subnet_id                       = azurerm_subnet.ANFDelegatedSubnet.id
  protocols                       = ["NFSv3"]
  security_style                  = "unix"
  storage_quota_in_gb             = var.netappVolumeSize
  snapshot_directory_visible      = true
  zone                            = var.anf_zone_number
  azure_vmware_data_store_enabled = true

  export_policy_rule {
    rule_index          = 1
    allowed_clients     = ["0.0.0.0/0"]
    protocols_enabled   = ["NFSv3"]
    root_access_enabled = true
    unix_read_only      = false
    unix_read_write     = true
  }

  lifecycle {
    ignore_changes = [zone]
  }
}

