data "azurerm_vmware_private_cloud" "avs_privatecloud" {
  provider            = azurerm.AVS-to-ANFdatastore-NewVnet
  name                = var.PrivateCloudName
  resource_group_name = var.PrivateCloudResourceGroup
}

data "azurerm_netapp_volume" "anf_datastorevolume" {
  provider = azurerm.AVS-to-ANFdatastore-NewVnet

  name                = var.netappVolumeName
  account_name        = var.netappAccountName
  pool_name           = var.netappCapacityPoolName
  resource_group_name = azurerm_resource_group.deploymentRG.name
}

resource "azapi_resource" "avs_datastore_attach_anfvolume" {
  type = "Microsoft.AVS/privateClouds/clusters/datastores@2021-12-01"
  depends_on = [
    azurerm_virtual_network_gateway_connection.expressRoute
  ]
  name      = var.netappVolumeName
  parent_id = "${data.azurerm_vmware_private_cloud.avs_privatecloud.id}/clusters/Cluster-1"
  body = {
    properties = {
      netAppVolume = {
        id = azurerm_netapp_volume.anf_volume.id
      }
    }
  }
}

terraform {
  required_providers {
    grid = {
      source = "threefoldtech/grid"
    }
  }
}
provider "grid" {
}

resource "grid_scheduler" "sched" {
  requests {
    name      = "node1"
    cru       = 2
    mru       = 1024
    yggdrasil = false
    wireguard = false
  }
  requests {
    name             = "node2"
    cru              = 2
    mru              = 1024
    public_config    = true
    public_ips_count = 1
    yggdrasil        = false
    wireguard        = false
  }
}

locals {
  name  = "myvm"
  name2 = "myvm2"
  node  = grid_scheduler.sched.nodes["node1"]
  node2 = grid_scheduler.sched.nodes["node2"]
}

resource "grid_network" "net1" {
  name        = local.name
  nodes       = [local.node, local.node2]
  ip_range    = "10.1.0.0/16"
  description = "newer network"
}
resource "grid_deployment" "d1" {
  name         = local.name
  node         = local.node
  network_name = grid_network.net1.name
  vms {
    name  = "vm1"
    flist = "https://hub.grid.tf/tf-official-apps/base:latest.flist"
    cpu   = 2
    # publicip   = true
    memory     = 1024
    entrypoint = "/sbin/zinit init"
    env_vars = {
      SSH_KEY = file("~/.ssh/id_rsa.pub")
    }
  }
}

resource "grid_deployment" "d2" {
  name         = local.name2
  node         = local.node2
  network_name = grid_network.net1.name
  vms {
    name       = "vm2"
    flist      = "https://hub.grid.tf/azmy.3bot/forwarder.flist"
    cpu        = 2
    publicip   = true
    memory     = 1024
    entrypoint = "/sbin/zinit init"
    env_vars = {
      SSH_KEY = file("~/.ssh/id_rsa.pub")
      TARGET  = grid_deployment.d1.vms[0].ip
    }
  }
}

output "computed_public_ip" {
  value = split("/", grid_deployment.d2.vms[0].computedip)[0]
}

