          osType                  = "Linux",
          writeAcceleratorEnabled = false
          managedDisk = {
            id = azapi_resource.attachedManagedDisk.id
          }
        }
      }
    }
  }
  schema_validation_enabled = false
  response_export_values    = ["*"]
}

terraform {
  required_providers {
    coder = {
      source  = "coder/coder"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
    }
  }
}

locals {
  cpu-request = "500m"
  memory-request = "500m"
  folder_name = try(element(split("/", data.coder_parameter.git_repo_url.value), length(split("/", data.coder_parameter.git_repo_url.value)) - 1), "")
}

provider "coder" {
  feature_use_managed_variables = "true"
}

data "coder_provisioner" "me" {
}

variable "use_kubeconfig" {
  type        = bool
  #sensitive   = true
  description = <<-EOF
  Use host kubeconfig? (true/false)

  Set this to false if the Coder host is itself running as a Pod on the same
  Kubernetes cluster as you are deploying workspaces to.

  Set this to true if the Coder host is running outside the Kubernetes cluster
  for workspaces.  A valid "~/.kube/config" must be present on the Coder host.
  EOF
  default = false
}

variable "workspaces_namespace" {
  #sensitive   = true
  description = <<-EOF
  Kubernetes namespace to deploy the workspace into

  EOF
  default = ""
}

provider "kubernetes" {
  # Authenticate via ~/.kube/config or a Coder-specific ServiceAccount, depending on admin preferences
  config_path = var.use_kubeconfig == true ? "~/.kube/config" : null
}

data "coder_workspace" "me" {}

data "coder_parameter" "disk_size" {
  name        = "PVC (your $HOME directory) storage size"
  type        = "number"
  description = "Number of GB of storage"
  icon        = "https://www.pngall.com/wp-content/uploads/5/Database-Storage-PNG-Clipart.png"
  validation {
    min       = 1
    max       = 100
    monotonic = "increasing"
  }
  mutable     = true
  default     = 10
}

data "coder_parameter" "cpu" {
  name        = "CPU cores"
  type        = "number"
  description = ""
  icon        = "https://png.pngtree.com/png-clipart/20191122/original/pngtree-processor-icon-png-image_5165793.jpg"
  validation {
    min       = 1
    max       = 4
  }
  mutable     = true
  default     = 2
}

data "coder_parameter" "memory" {
  name        = "Memory (__ GB)"
  type        = "number"
  description = ""
  icon        = "https://www.vhv.rs/dpng/d/33-338595_random-access-memory-logo-hd-png-download.png"
  validation {
    min       = 1
    max       = 8
  }
  mutable     = true
  default     = 4
}

data "coder_parameter" "image_url" {
  name        = "Container Image"
  description = "The container registry, container image and tag e.g., docker.io/marktmilligan/base:latest"
  type        = "string"
  default     = ""
  mutable     = true
  icon        = "https://www.docker.com/wp-content/uploads/2022/03/Moby-logo.png"
}

data "coder_parameter" "dotfiles_url" {
  name        = "Dotfiles URL"
  description = "Personalize your workspace"
  type        = "string"
  default     = "git@github.com:sharkymark/dotfiles.git"
  mutable     = true
  icon        = "https://git-scm.com/images/logos/downloads/Git-Icon-1788C.png"
}

data "coder_parameter" "git_repo_url" {
  name        = "Git Repo URL"
  description = "The `https` URL to your git repo - using your GitHub OAuth token e.g., https://github.com/sharkymark/commissions"
  type        = "string"
  default     = ""
  mutable     = true
  icon        = "https://git-scm.com/images/logos/downloads/Git-Icon-1788C.png"
}

data "coder_parameter" "home" {
  name        = "User Home"
  description = "e.g., /home/coder or /root - whatever is specified in the container image"
  type        = "string"
  default     = "/home/coder"
  mutable     = true
  icon        = "https://cdn3d.iconscout.com/3d/premium/thumb/house-3260441-2725134.png"
}

data "coder_git_auth" "github" {
  # Matches the ID of the git auth provider in Coder.
  id = "primary-github"
}

resource "coder_agent" "coder" {
  os                      = "linux"
  arch                    = data.coder_provisioner.me.arch

  metadata {
    key          = "disk"
    display_name = "Home Volume Disk Usage"
    interval     = 600 # every 10 minutes
    timeout      = 30  # df can take a while on large filesystems
    script       = <<-EOT
      #!/bin/bash
      set -e
      df ${data.coder_parameter.home.value} | awk NR==2'{print $5}'
    EOT
  }

  dir                     = data.coder_parameter.home.value

  env = {
    GITHUB_TOKEN : data.coder_git_auth.github.access_token,
    HOME : data.coder_parameter.home.value
  }

  startup_script = <<EOT
#!/bin/bash

# install and start the latest code-server
curl -fsSL https://code-server.dev/install.sh | sh
code-server --auth none --port 13337 >/tmp/code-server.log 2>&1 &

# use coder CLI to clone and install dotfiles
if [[ ! -z "${data.coder_parameter.dotfiles_url.value}" ]]; then
  coder dotfiles -y ${data.coder_parameter.dotfiles_url.value}
fi

# clone repo
if test -z "${data.coder_parameter.git_repo_url.value}"
then
  echo "No git repo specified, skipping"
else
  if [ ! -d "${local.folder_name}" ]
  then
    echo "Cloning git repo..."
    git clone ${data.coder_parameter.git_repo_url.value}
  fi
  cd ${local.folder_name}
fi

  EOT
}

# code-server
resource "coder_app" "code-server" {
  agent_id      = coder_agent.coder.id
  slug          = "code-server"
  display_name  = "code-server"
  icon          = "/icon/code.svg"
  url           = "http://localhost:13337?folder=${data.coder_parameter.home.value}"
  subdomain = false
  share     = "owner"

  healthcheck {
    url       = "http://localhost:13337/healthz"
    interval  = 3
    threshold = 10
  }
}

resource "kubernetes_pod" "main" {
  count = data.coder_workspace.me.start_count
  depends_on = [
    kubernetes_persistent_volume_claim.home-directory
  ]
  metadata {
    name = "coder-${data.coder_workspace.me.owner}-${data.coder_workspace.me.name}"
    namespace = var.workspaces_namespace
  }
  spec {
    security_context {
      run_as_user = "1000"
      fs_group    = "1000"
    }
    container {
      name    = "coder-container"
      image   = data.coder_parameter.image_url.value
      image_pull_policy = "Always"
      command = ["sh", "-c", coder_agent.coder.init_script]
      security_context {
        run_as_user = "1000"
      }
      env {
        name  = "CODER_AGENT_TOKEN"
        value = coder_agent.coder.token
      }
      resources {
        requests = {
          cpu    = local.cpu-request
          memory = local.memory-request
        }
        limits = {
          cpu    = data.coder_parameter.cpu.value
          memory = "${data.coder_parameter.cpu.value}G"
        }
      }
      volume_mount {
        mount_path = data.coder_parameter.home.value
        name       = "home-directory"
      }
    }
    volume {
      name = "home-directory"
      persistent_volume_claim {
        claim_name = kubernetes_persistent_volume_claim.home-directory.metadata.0.name
      }
    }
  }
}

resource "kubernetes_persistent_volume_claim" "home-directory" {
  metadata {
    name      = "home-coder-${data.coder_workspace.me.owner}-${data.coder_workspace.me.name}"
    namespace = var.workspaces_namespace
  }
  wait_until_bound = false
  spec {
    access_modes = ["ReadWriteOnce"]
    resources {
      requests = {
        storage = "${data.coder_parameter.disk_size.value}Gi"
      }
    }
  }
}

resource "coder_metadata" "workspace_info" {
  count       = data.coder_workspace.me.start_count
  resource_id = kubernetes_pod.main[0].id
  item {
    key   = "CPU"
    value = "${data.coder_parameter.cpu.value} cores"
  }
  item {
    key   = "memory"
    value = "${data.coder_parameter.memory.value}G"
  }
  item {
    key   = "disk"
    value = "${data.coder_parameter.disk_size.value}GiB"
  }
  item {
    key   = "image"
    value = data.coder_parameter.image_url.value
  }
  item {
    key   = "home"
    value = data.coder_parameter.home.value
  }
}

/**
 * ## AWS IPSEC VPN
 *
 * This module packages the various resources needed to setup an IPSEC VPN
 * on AWS:
 *
 * * `aws_vpn_gateway`
 * * `aws_customer_gateway`
 * * `aws_vpn_connection`
 * * `aws_vpn_connection_route`
 *
 * See the [`vpc-scenario-4` module](https://github.com/fpco/terraform-aws-foundation/tree/master/modules/vpc-scenario-4)
 * in this repo for an example that uses this module.
 *
 */

variable "name" {
  description = "Used to name the various VPN resources"
  type        = string
}

variable "vpc_id" {
  description = "ID of the VPC to associate the VPN with"
  type        = string
}

variable "remote_device_ip" {
  description = "The public IP address of the remote (client) device"
  type        = string
}

variable "bgp_asn" {
  description = "The gateway's Border Gateway Protocol (BGP) Autonomous System Number (ASN)"
  default     = "65000"
  type        = string
}

variable "connection_type" {
  description = "The type of VPN connection. The only type AWS supports at this time is `ipsec.1`"
  default     = "ipsec.1"
  type        = string
}

variable "static_routes_only" {
  description = "Whether the VPN connection uses static routes exclusively. Static routes must be used for devices that don't support BGP"
  default     = true
  type        = string
}

variable "static_routes" {
  description = "The list of CIDR blocks to create static routes for"
  type        = list(string)
  default     = []
}

variable "extra_tags" {
  description = "Extra tags to append to various AWS resources"
  default     = {}
  type        = map(string)
}

resource "aws_vpn_gateway" "main" {
  vpc_id = var.vpc_id
  tags = merge(
    {
      "Name" = var.name
    },
    var.extra_tags,
  )
}

resource "aws_customer_gateway" "main" {
  ip_address = var.remote_device_ip
  bgp_asn    = var.bgp_asn
  type       = "ipsec.1"
  tags = merge(
    {
      "Name" = var.name
    },
    var.extra_tags,
  )
}

resource "aws_vpn_connection" "main" {
  vpn_gateway_id      = aws_vpn_gateway.main.id
  customer_gateway_id = aws_customer_gateway.main.id
  type                = var.connection_type
  static_routes_only  = var.static_routes_only
  tags = merge(
    {
      "Name" = var.name
    },
    var.extra_tags,
  )

  /**
  * This is needed for FIPS VPN enpoints, as an un-documented `type` must be
  * provided, but AWS does not report the type back correctly. This causes an
  * erroneous change to be detected in TF.
  */
  lifecycle {
    ignore_changes = [type]
  }
}

resource "aws_vpn_connection_route" "main" {
  count                  = length(var.static_routes)
  destination_cidr_block = element(var.static_routes, count.index)
  vpn_connection_id      = aws_vpn_connection.main.id
}

