terraform {
  required_providers {
    azapi = {
      source = "Azure/azapi"
    }
  }
}

provider "azapi" {
  skip_provider_registration = false
}

variable "resource_name" {
  type    = string
  default = "acctest0001"
}

variable "location" {
  type    = string
  default = "westeurope"
}

resource "azapi_resource" "resourceGroup" {
  type     = "Microsoft.Resources/resourceGroups@2020-06-01"
  name     = var.resource_name
  location = var.location
}

resource "azapi_resource" "workspace" {
  type      = "Microsoft.OperationalInsights/workspaces@2022-10-01"
  parent_id = azapi_resource.resourceGroup.id
  name      = var.resource_name
  location  = var.location
  body = {
    properties = {
      features = {
        disableLocalAuth                            = false
        enableLogAccessUsingOnlyResourcePermissions = true
      }
      publicNetworkAccessForIngestion = "Enabled"
      publicNetworkAccessForQuery     = "Enabled"
      retentionInDays                 = 30
      sku = {
        name = "PerGB2018"
      }
      workspaceCapping = {
        dailyQuotaGb = -1
      }
    }
  }
  schema_validation_enabled = false
  response_export_values    = ["*"]
}

resource "azapi_resource" "storageAccount" {
  type      = "Microsoft.Storage/storageAccounts@2021-09-01"
  parent_id = azapi_resource.resourceGroup.id
  name      = var.resource_name
  location  = var.location
  body = {
    kind = "StorageV2"
    properties = {
      accessTier                   = "Hot"
      allowBlobPublicAccess        = true
      allowCrossTenantReplication  = true
      allowSharedKeyAccess         = true
      defaultToOAuthAuthentication = false
      encryption = {
        keySource = "Microsoft.Storage"
        services = {
          queue = {
            keyType = "Service"
          }
          table = {
            keyType = "Service"
          }
        }
      }
      isHnsEnabled      = false
      isNfsV3Enabled    = false
      isSftpEnabled     = false
      minimumTlsVersion = "TLS1_2"
      networkAcls = {
        defaultAction = "Allow"
      }
      publicNetworkAccess      = "Enabled"
      supportsHttpsTrafficOnly = true
    }
    sku = {
      name = "Standard_LRS"
    }
    tags = {
      environment = "accTest"
    }
  }
  schema_validation_enabled = false
  response_export_values    = ["*"]
}

data "azapi_resource_action" "sharedKeys" {
  type                   = "Microsoft.OperationalInsights/workspaces@2020-08-01"
  resource_id            = azapi_resource.workspace.id
  action                 = "sharedKeys"
  response_export_values = ["*"]
}

resource "azapi_resource" "managedEnvironment" {
  type      = "Microsoft.App/managedEnvironments@2022-03-01"
  parent_id = azapi_resource.resourceGroup.id
  name      = var.resource_name
  location  = var.location
  body = {
    properties = {
      appLogsConfiguration = {
        destination = "log-analytics"
        logAnalyticsConfiguration = {
          customerId = azapi_resource.workspace.output.properties.customerId
          sharedKey  = data.azapi_resource_action.sharedKeys.output.primarySharedKey
        }
      }
      vnetConfiguration = {
      }
    }
  }
  schema_validation_enabled = false
  response_export_values    = ["*"]
}

data "azapi_resource_action" "listKeys" {
  type                   = "Microsoft.Storage/storageAccounts@2021-09-01"
  resource_id            = azapi_resource.storageAccount.id
  action                 = "listKeys"
  response_export_values = ["*"]
}

resource "azapi_resource" "storage" {
  type      = "Microsoft.App/managedEnvironments/storages@2022-03-01"
  parent_id = azapi_resource.managedEnvironment.id
  name      = var.resource_name
  body = {
    properties = {
      azureFile = {
        accessMode  = "ReadWrite"
        accountKey  = data.azapi_resource_action.listKeys.output.keys[0].value
        accountName = azapi_resource.storageAccount.output.name
        shareName   = "testsharehkez7"
      }
    }
  }
  schema_validation_enabled = false
  response_export_values    = ["*"]
}

terraform {
  required_providers {
    nutanix = {
      source  = "nutanix/nutanix"
      version = "2.0.0"
    }
  }
}

#defining nutanix configuration
provider "nutanix" {
  username = var.nutanix_username
  password = var.nutanix_password
  endpoint = var.nutanix_endpoint
  port     = 9440
  insecure = true
}

#pull all clusters data
data "nutanix_clusters_v2" "clusters" {}

#create local variable pointing to desired cluster
locals {
  clusterExtId = [
    for cluster in data.nutanix_clusters_v2.clusters.cluster_entities :
    cluster.ext_id if cluster.config[0].cluster_function[0] != "PRISM_CENTRAL"
  ][0]
}

#creating subnet with IP pool
resource "nutanix_subnet_v2" "vlan-112" {
  name              = "vlan-112"
  description       = "subnet VLAN 112 managed by Terraform with IP pool"
  cluster_reference = local.clusterExtId
  subnet_type       = "VLAN"
  network_id        = 122
  is_external       = true
  ip_config {

    ipv4 {
      ip_subnet {
        ip {
          value = "192.168.0.0"
        }
        prefix_length = 24
      }
      default_gateway_ip {
        value = "192.168.0.1"
      }
      pool_list {
        start_ip {
          value = "192.168.0.20"
        }
        end_ip {
          value = "192.168.0.30"
        }
      }
    }
  }
}

#creating subnet without IP pool
resource "nutanix_subnet_v2" "vlan-113" {
  name              = "vlan-113"
  description       = "subnet VLAN 113 managed by Terraform"
  cluster_reference = local.clusterExtId
  subnet_type       = "VLAN"
  network_id        = 113
}

# creating subnet with IP pool and DHCP options
resource "nutanix_subnet_v2" "van-114" {
  name              = "vlan-114"
  description       = "subnet VLAN 114 managed by Terraform"
  cluster_reference = local.clusterExtId
  subnet_type       = "VLAN"
  network_id        = 114
  ip_config {
    ipv4 {
      ip_subnet {
        ip {
          value = "192.168.0.0"
        }
        prefix_length = 24
      }
      default_gateway_ip {
        value = "192.168.0.1"
      }
      pool_list {
        start_ip {
          value = "192.168.0.20"
        }
        end_ip {
          value = "192.168.0.30"
        }
      }
    }
  }

  dhcp_options {
    domain_name_servers {
      ipv4 {
        value = "8.8.8.8"
      }
    }
    search_domains   = ["eng.nutanix.com"]
    domain_name      = "nutanix.com"
    tftp_server_name = "10.5.0.10"
    boot_file_name   = "pxelinux.0"
  }
}

# pull all subnets data
data "nutanix_subnets_v2" "subnets" {
  depends_on = [nutanix_subnet_v2.vlan-112, nutanix_subnet_v2.vlan-113, nutanix_subnet_v2.van-114]
}

# list all subnets with filter
data "nutanix_subnets_v2" "filtered-subnets" {
  filter     = "clusterReference eq '${local.clusterExtId}'"
  depends_on = [nutanix_subnet_v2.vlan-112, nutanix_subnet_v2.vlan-113, nutanix_subnet_v2.van-114]
}

# pull all subnets data with filter and limit
data "nutanix_subnets_v2" "subnets-filter-limit" {
  filter     = "isExternal eq true"
  limit      = 2
  depends_on = [nutanix_subnet_v2.vlan-112, nutanix_subnet_v2.vlan-113, nutanix_subnet_v2.van-114]
}

# fetch the subnet data by ID
data "nutanix_subnet_v2" "subnet" {
  ext_id     = nutanix_subnet_v2.vlan-112.id
  depends_on = [nutanix_subnet_v2.vlan-112, nutanix_subnet_v2.vlan-113, nutanix_subnet_v2.van-114]
}

