resource "linode_nodebalancer_config" "foo-https" {
  port            = 443
  nodebalancer_id = linode_nodebalancer.foo-nb.id
  protocol        = "http"
  algorithm       = "roundrobin"
  stickiness      = "none"
  check           = "http_body"
  check_interval  = "90"
  check_timeout   = "10"
  check_attempts  = "3"
  check_path      = "/test/"
  check_body      = "it works"
  check_passive   = true
  cipher_suite    = "recommended"
  # ssl_cert FUTURE pair with letsencrypt resource
  # ssl_key FUTURE pair with letsencrypt resource
  # https://opencredo.com/letsencrypt-terraform/
}

resource "linode_nodebalancer_config" "foo-http" {
  port            = 80
  nodebalancer_id = linode_nodebalancer.foo-nb.id
  protocol        = "http"
  algorithm       = "roundrobin"
  stickiness      = "none"
  check           = "http_body"
  check_interval  = "90"
  check_timeout   = "10"
  check_attempts  = "3"
  check_path      = "/test/"
  check_body      = "it works"
  check_passive   = true
}

resource "linode_nodebalancer_node" "foo-http-www" {
  count           = var.nginx_count
  nodebalancer_id = linode_nodebalancer.foo-nb.id
  config_id       = linode_nodebalancer_config.foo-https.id
  label           = "${random_pet.project.id}_http_${count.index}"

  address = "${element(linode_instance.nginx.*.private_ip_address, count.index)}:80"
  weight  = 50
  mode    = "accept"
}

resource "linode_nodebalancer_node" "foo-https-www" {
  count           = var.nginx_count
  nodebalancer_id = linode_nodebalancer.foo-nb.id
  config_id       = linode_nodebalancer_config.foo-http.id
  label           = "${random_pet.project.id}_https_${count.index}"

  address = "${element(linode_instance.nginx.*.private_ip_address, count.index)}:80"
  weight  = 50
  mode    = "accept"
}

resource "linode_domain" "foo-com" {
  soa_email   = "${random_pet.project.id}@${substr(sha256(random_pet.project.id), 0, 8)}example.com"
  ttl_sec     = "300"
  expire_sec  = "300"
  refresh_sec = "300"
  domain      = "${random_pet.project.id}example.com"
  type        = "master"
}

resource "linode_domain_record" "A-root" {
  domain_id   = linode_domain.foo-com.id
  record_type = "A"
  name        = ""
  target      = linode_nodebalancer.foo-nb.ipv4
}

resource "linode_domain_record" "A-nginx" {
  count       = var.nginx_count
  domain_id   = linode_domain.foo-com.id
  name        = element(linode_instance.nginx.*.label, count.index)
  record_type = "A"
  target      = element(linode_instance.nginx.*.ip_address, count.index)
}

resource "linode_domain_record" "AAAA-root" {
  domain_id   = linode_domain.foo-com.id
  record_type = "AAAA"
  name        = ""
  target      = linode_nodebalancer.foo-nb.ipv6
}

resource "linode_domain_record" "CNAME-www" {
  domain_id   = linode_domain.foo-com.id
  record_type = "CNAME"
  name        = "www"
  target      = linode_domain.foo-com.domain
}

resource "linode_instance" "nginx" {
  count = var.nginx_count
  label = "${random_pet.project.id}-nginx-${count.index + 1}"

  group             = "foo"
  region            = linode_nodebalancer.foo-nb.region
  type              = data.linode_instance_type.default.id
  private_ip        = true
  boot_config_label = "nginx"

  connection {
    host        = self.ip_address
    type        = "ssh"
    user        = "root"
    agent       = "false"
    private_key = chomp(file(var.private_ssh_key))
  }

  disk {
    label           = "boot"
    size            = data.linode_instance_type.default.disk / 2
    authorized_keys = [chomp(file(var.public_ssh_key))]
    root_pass       = "${random_string.password.result}"
    image           = data.linode_image.ubuntu.id
  }

  config {
    label  = "nginx"
    kernel = "linode/latest-64bit"

    devices {
      sda {
        disk_label = "boot"
      }

      sdb {
        volume_id = element(linode_volume.nginx-vol.*.id, count.index)
      }
    }
  }

  provisioner "remote-exec" {
    inline = [
      "export PATH=$PATH:/usr/bin",
      "apt-get -q update",
      "mkfs ${element(linode_volume.nginx-vol.*.filesystem_path, count.index)}",
      "mkdir -p /var/www/html/",
      "echo ${element(linode_volume.nginx-vol.*.filesystem_path, count.index)} /var/www/html ext4 defaults 0 2 | sudo tee -a /etc/fstab",
      "mount -a",
      "mkdir -p /var/www/html/test",
      "echo it works > /var/www/html/test/index.html",
      "echo node ${count.index + 1} > /var/www/html/index.html",
      "apt-get -q -y install nginx",
    ]
  }
}

resource "linode_volume" "nginx-vol" {
  count  = var.nginx_count
  region = linode_nodebalancer.foo-nb.region
  size   = 10
  label  = "${random_pet.project.id}-vol-${count.index}"
}

resource "linode_volume" "simple-vol-lateattachment" {
  region    = linode_instance.simple.region
  size      = 10
  label     = "${random_pet.project.id}-simple"
  linode_id = linode_instance.simple.id

  connection {
    host        = linode_instance.simple.ip_address
    type        = "ssh"
    user        = "root"
    agent       = "false"
    private_key = chomp(file(var.private_ssh_key))
  }

  provisioner "remote-exec" {
    inline = [
      "export PATH=$PATH:/usr/bin",
      "timeout 180 sh -c 'while ! ls ${self.filesystem_path}; do sleep 1; done'",
      "sudo mkfs ${self.filesystem_path}",
      "mkdir -p /var/www/html/",
      "echo ${self.filesystem_path} /var/www/html ext4 defaults 0 2 | sudo tee -a /etc/fstab",
      "mount -a",
      "mkdir -p /var/www/html/test",
      "echo it works > /var/www/html/test/index.html",
      "echo so simple > /var/www/html/index.html",
    ]
  }
}

resource "linode_stackscript" "install-nginx" {
  label       = "install-nginx"
  description = "Update system software and install nginx."

  script = <<EOF
#!/bin/bash
# <UDF name="package" label="System Package to Install" example="nginx" default="">
export PATH=$PATH:/usr/bin
apt-get -q update
echo unattended-upgrades unattended-upgrades/enable_auto_updates boolean true | debconf-set-selections
apt-get -q -y install unattended-upgrades $PACKAGE
EOF

  images   = ["linode/ubuntu22.04", "linode/ubuntu20.04"]
  rev_note = "initial script"
}

resource "linode_sshkey" "mykey" {
  ssh_key = chomp(file(var.public_ssh_key))
  label   = "Terraform SSHKey"
}

resource "linode_instance" "simple" {
  image = "linode/ubuntu22.04"
  label = "${random_pet.project.id}-simple"

  group            = "foo"
  tags             = ["terraform"]
  region           = var.region
  type             = "g6-nanode-1"
  authorized_users = [data.linode_profile.me.username]
  stackscript_id   = linode_stackscript.install-nginx.id

  stackscript_data = {
    "package" = "nginx"
  }
}

data "linode_networking_ip" "simple_v4" {
  address = linode_instance.simple.ip_address
}

data "linode_networking_ip" "simple_v6" {
  address = replace(linode_instance.simple.ipv6, "/128", "")
}

terraform {
  required_providers {
    azurecaf = {
      source  = "aztfmod/azurecaf"
      version = "1.2.26"
    }
  }
}

resource "azurecaf_name" "virtual_network" {
  name          = var.application_name
  resource_type = "azurerm_virtual_network"
  suffixes      = [var.environment]
}

resource "azurerm_virtual_network" "virtual_network" {
  name                = azurecaf_name.virtual_network.result
  address_space       = [var.address_space]
  location            = var.location
  resource_group_name = var.resource_group

  tags = {
    "environment"      = var.environment
    "application-name" = var.application_name
  }
}

resource "azurecaf_name" "service_subnet" {
  name          = var.application_name
  resource_type = "azurerm_subnet"
  suffixes      = [var.environment, "svc"]
}

resource "azurerm_subnet" "service_subnet" {
  name                 = azurecaf_name.service_subnet.result
  resource_group_name  = var.resource_group
  virtual_network_name = azurerm_virtual_network.virtual_network.name
  address_prefixes     = [var.service_subnet_prefix]
}

resource "azurecaf_name" "app_subnet" {
  name          = var.application_name
  resource_type = "azurerm_subnet"
  suffixes      = [var.environment, "app"]
}

resource "azurerm_subnet" "app_subnet" {
  name                 = azurecaf_name.app_subnet.result
  resource_group_name  = var.resource_group
  virtual_network_name = azurerm_virtual_network.virtual_network.name
  address_prefixes     = [var.app_subnet_prefix]
  service_endpoints    = var.service_endpoints
}

resource "azurecaf_name" "database_subnet" {
  name          = var.application_name
  resource_type = "azurerm_subnet"
  suffixes      = [var.environment, "database"]
}

resource "azurerm_subnet" "database_subnet" {
  name                 = azurecaf_name.database_subnet.result
  resource_group_name  = var.resource_group
  virtual_network_name = azurerm_virtual_network.virtual_network.name
  address_prefixes     = [var.database_subnet_prefix]
  service_endpoints   = ["Microsoft.Storage"]
  delegation {
    name = "fs"
    service_delegation {
      name = "Microsoft.DBforPostgreSQL/flexibleServers"
      actions = ["Microsoft.Network/virtualNetworks/subnets/join/action"]
    }
  }
}

resource "azurecaf_name" "redis_subnet" {
  name          = var.application_name
  resource_type = "azurerm_subnet"
  suffixes      = [var.environment, "redis"]
}

resource "azurerm_subnet" "redis_subnet" {
  name                 = azurecaf_name.redis_subnet.result
  resource_group_name  = var.resource_group
  virtual_network_name = azurerm_virtual_network.virtual_network.name
  address_prefixes     = [var.redis_subnet_prefix]
}

locals {
  endpoint_name               = "${var.stack_id}-cdn"
  default_origin_group_name   = "${var.stack_id}-default-origin-group"
  default_origin_name         = "${var.stack_id}-default-origin"

  changed_path_md5_hashes     = join("", sort(values(var.uploaded_files)))
}

# Create the CDN profile for the website
resource "azurerm_cdn_frontdoor_profile" "cdn_profile" {
  name                = "${var.stack_id}-cdn-profile"
  resource_group_name = var.resource_group_name
  sku_name            = "Standard_AzureFrontDoor"
}

resource "azurerm_cdn_frontdoor_endpoint" "cdn_endpoint" {
  name                     = local.endpoint_name
  cdn_frontdoor_profile_id = azurerm_cdn_frontdoor_profile.cdn_profile.id
}

data "azurerm_dns_zone" "dns_zone" {
  count = var.enable_custom_domain ? 1 : 0
  name  = var.zone_name
  resource_group_name = var.zone_resource_group_name
}

resource "azurerm_cdn_frontdoor_custom_domain" "custom_domain" {
  count                    = var.enable_custom_domain ? 1 : 0
  name                     = var.domain_name
  cdn_frontdoor_profile_id = azurerm_cdn_frontdoor_profile.cdn_profile.id
  dns_zone_id              = data.azurerm_dns_zone.dns_zone[0].id
  host_name                = var.custom_domain_host_name

  tls {
    certificate_type    = "ManagedCertificate"
  }
}

resource "azurerm_cdn_frontdoor_custom_domain_association" "custom_domain_association" {
  count                          = var.enable_custom_domain ? 1 : 0
  cdn_frontdoor_custom_domain_id = azurerm_cdn_frontdoor_custom_domain.custom_domain[0].id
  cdn_frontdoor_route_ids        = [
    azurerm_cdn_frontdoor_route.main_route.id
  ]
}

resource "azurerm_dns_txt_record" "validate_domain" {
  count               = var.enable_custom_domain ? 1 : 0
  name                = var.is_apex_domain ? "_dnsauth" : join(".", ["_dnsauth", var.domain_name])
  zone_name           = data.azurerm_dns_zone.dns_zone[0].name
  resource_group_name = var.zone_resource_group_name
  ttl                 = 3600

  record {
    value = azurerm_cdn_frontdoor_custom_domain.custom_domain[0].validation_token
  }

  depends_on = [ azurerm_cdn_frontdoor_custom_domain.custom_domain ]
}

resource "azurerm_cdn_frontdoor_origin_group" "default_origin_group" {
  name                     = local.default_origin_group_name
  cdn_frontdoor_profile_id = azurerm_cdn_frontdoor_profile.cdn_profile.id

  # https://learn.microsoft.com/en-us/azure/frontdoor/origin?pivots=front-door-standard-premium#load-balancing-settings
  load_balancing {
    additional_latency_in_milliseconds = 200 # Lower latency tolerance for faster failover
    sample_size                        = 5 # More samples for better decision-making
    successful_samples_required        = 3 # Keep at 3 to maintain reliability
  }
}

resource "azurerm_cdn_frontdoor_origin" "default_origin" {
  name                          = local.default_origin_name
  cdn_frontdoor_origin_group_id = azurerm_cdn_frontdoor_origin_group.default_origin_group.id

  certificate_name_check_enabled = false
  enabled            = true

  host_name          = var.primary_web_host
  http_port          = 80
  https_port         = 443
  origin_host_header = var.primary_web_host

  depends_on = [ azurerm_cdn_frontdoor_origin_group.default_origin_group ]
}

# create default ruleset for default rules
resource "azurerm_cdn_frontdoor_rule_set" "default_ruleset" {
  name                      = "defaultruleset"
  cdn_frontdoor_profile_id  = azurerm_cdn_frontdoor_profile.cdn_profile.id
}

resource "azurerm_cdn_frontdoor_rule" "redirect_slash_rule" {
  name                      = "redirectslash"
  cdn_frontdoor_rule_set_id = azurerm_cdn_frontdoor_rule_set.default_ruleset.id
  order                     = 1

  conditions {
    url_path_condition {
      operator         = "RegEx"
      match_values     = [".*\\/$"]
    }
  }

  actions {
    url_redirect_action {
      redirect_type        = "Found"
      redirect_protocol    = "MatchRequest"
      destination_path     = "/{url_path:0:-1}"
      destination_hostname = ""
    }
  }

  depends_on = [ azurerm_cdn_frontdoor_rule_set.default_ruleset ]
}

# create default ruleset if apis are present
resource "azurerm_cdn_frontdoor_rule_set" "api_ruleset" {
  count                     = var.enable_api_rewrites ? 1 : 0
  name                      = "apiruleset"
  cdn_frontdoor_profile_id  = azurerm_cdn_frontdoor_profile.cdn_profile.id
}

# Create the CDN route
resource "azurerm_cdn_frontdoor_route" "main_route" {
  name                       = "${var.stack_id}-main-route"
  cdn_frontdoor_endpoint_id =  azurerm_cdn_frontdoor_endpoint.cdn_endpoint.id
  cdn_frontdoor_origin_group_id = azurerm_cdn_frontdoor_origin_group.default_origin_group.id
  cdn_frontdoor_origin_ids = [
    azurerm_cdn_frontdoor_origin.default_origin.id
  ]
  cdn_frontdoor_rule_set_ids = var.enable_api_rewrites ? [azurerm_cdn_frontdoor_rule_set.default_ruleset.id, azurerm_cdn_frontdoor_rule_set.api_ruleset[0].id] : [azurerm_cdn_frontdoor_rule_set.default_ruleset.id]
  supported_protocols = [ "Https" ]
  https_redirect_enabled = false
  patterns_to_match =  [
    "/*"
  ]

  cdn_frontdoor_custom_domain_ids = var.enable_custom_domain ? [azurerm_cdn_frontdoor_custom_domain.custom_domain[0].id] : []

  cache {
    query_string_caching_behavior = "IgnoreQueryString"
    compression_enabled = true
    content_types_to_compress     = [
      "text/html", "text/css", "application/javascript",
      "application/json", "image/svg+xml"
    ]
  }

  depends_on = [
    azurerm_cdn_frontdoor_profile.cdn_profile,
    azurerm_cdn_frontdoor_endpoint.cdn_endpoint,
    azurerm_cdn_frontdoor_origin_group.default_origin_group,
    azurerm_cdn_frontdoor_origin.default_origin,
    azurerm_cdn_frontdoor_rule_set.default_ruleset,
    azurerm_cdn_frontdoor_rule_set.api_ruleset
  ]
}

resource "azurerm_dns_cname_record" "add_dns_cname" {
  count               = var.enable_custom_domain && !var.is_apex_domain ? 1 : 0

  name                = var.domain_name
  zone_name           = data.azurerm_dns_zone.dns_zone[0].name
  resource_group_name = var.zone_resource_group_name
  ttl                 = 3600
  record              = azurerm_cdn_frontdoor_endpoint.cdn_endpoint.host_name

  depends_on = [
    azurerm_cdn_frontdoor_custom_domain.custom_domain,
    azurerm_cdn_frontdoor_route.main_route,
    azurerm_cdn_frontdoor_endpoint.cdn_endpoint
  ]
}

resource "azurerm_dns_a_record" "add_apex_record" {
  count               = var.enable_custom_domain && var.is_apex_domain ? 1 : 0

  name                = "@"
  zone_name           = data.azurerm_dns_zone.dns_zone[0].name
  resource_group_name = var.zone_resource_group_name
  ttl                 = 3600
  target_resource_id  = azurerm_cdn_frontdoor_endpoint.cdn_endpoint.id

  depends_on = [
    azurerm_cdn_frontdoor_custom_domain.custom_domain,
    azurerm_cdn_frontdoor_route.main_route,
    azurerm_cdn_frontdoor_endpoint.cdn_endpoint
  ]
}

data "azurerm_subscription" "current" {}

locals {
  // Check if the current OS is Windows by checking the drive letter in the path
  is_windows = can(regex("^[A-Za-z]:/", abspath(path.root)))
}

resource "terraform_data" "endpoint_purge" {
  count = var.skip_cache_invalidation ? 0 : 1

  # This will run on every Terraform apply
  triggers_replace = [
    # Force this to run on every apply when paths are changed
    local.changed_path_md5_hashes
  ]

  provisioner "local-exec" {
    command     = "az afd endpoint purge -g ${var.resource_group_name} --profile-name ${sensitive(azurerm_cdn_frontdoor_profile.cdn_profile.name)} --endpoint-name ${sensitive(local.endpoint_name)} --subscription ${sensitive(data.azurerm_subscription.current.subscription_id)} --content-paths \"/*\" --no-wait"
    interpreter = local.is_windows ? ["powershell", "-Command"] : null
  }

  depends_on = [azurerm_cdn_frontdoor_endpoint.cdn_endpoint]
}

