# Copyright IBM Corp. 2014, 2025
# SPDX-License-Identifier: MPL-2.0

provider "azurerm" {
  features {}
}

module "naming" {
  source  = "Azure/naming/azurerm"
  version = "0.4.0"
  prefix  = [var.prefix]
}

resource "azurerm_resource_group" "example" {
  name     = module.naming.resource_group.name
  location = var.location
}

resource "azurerm_iothub_dps_certificate" "example" {
  name                = module.naming.iothub_dps_certificate.name
  resource_group_name = azurerm_resource_group.example.name
  iot_dps_name        = var.iot_hub_dps_name
  certificate_content = filebase64(var.dps_cert_content)
  is_verified         = false
}

resource "random_string" "suffix" {
  length  = 5
  upper   = false
  lower   = true
  numeric = false
  special = false
}

# Event trigger once a day
resource "aws_cloudwatch_event_rule" "once_a_day" {
  name                = "${var.name}-log-export-run-lambda-${random_string.suffix.result}"
  description         = "Trigger lambda function that grabs yesterdays Cloudwatch logs and sends them to an S3 bucket with CreateExportTask"
  schedule_expression = var.trigger_schedule_expression
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.once_a_day.name
  target_id = "${var.name}-ExportLogsLambdaTarget-${random_string.suffix.result}"
  arn       = aws_lambda_function.log_exporter.arn
}

resource "aws_lambda_permission" "allow_triggering_function" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.log_exporter.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.once_a_day.arn
}

# Lambda function
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_dir  = "${path.module}/src/lambda/"
  output_path = "${path.module}/src/tmp/lambda.zip"
}

resource "aws_lambda_function" "log_exporter" {
  function_name    = "${var.name}-ExportLogsLambda-${random_string.suffix.result}"
  role             = aws_iam_role.log_exporter.arn
  handler          = "index.handler"
  filename         = "${path.module}/src/tmp/lambda.zip"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "nodejs22.x"
  timeout          = var.lambda_timeout

  environment {
    variables = {
      EXPORT_BUCKET = module.logs_export_bucket.bucket_name
      LOG_GROUPS    = jsonencode(var.log_groups_list)
      BUCKET_PREFIX = var.bucket_prefix
      DAYS_BEFORE   = var.export_days_before
      RETRY         = var.check_retry_attempts
      RETRY_TIMEOUT = var.check_retry_timeout
    }
  }
  tracing_config {
    mode = "Active"
  }
}

# IAM for lambda function
resource "aws_iam_role" "log_exporter" {
  name               = "${var.name}-log-s3-export-${random_string.suffix.result}"
  assume_role_policy = data.aws_iam_policy_document.log_exporter_sts.json
}

data "aws_iam_policy_document" "log_exporter_sts" {

  statement {
    sid = "UseByLambda"
    actions = [
      "sts:AssumeRole"
    ]
    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "log_exporter" {

  statement {
    sid = "LogsAccess"
    actions = [
      "logs:CreateExportTask",
      "logs:Describe*",
      "logs:ListTagsLogGroup",
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents"
    ]
    resources = ["*"]
  }

  statement {
    sid = "S3BucketAccess"
    actions = [
      "s3:PutObject",
      "s3:PutObjectAcl",
      "s3:PutBucketAcl",
      "s3:GetBucketAcl"
    ]
    resources = ["${module.logs_export_bucket.bucket_arn}/*"]
  }
  depends_on = [
    module.logs_export_bucket
  ]
}

resource "aws_iam_policy" "log_exporter" {
  name   = "${var.name}-log-exporter-policy-${random_string.suffix.result}"
  policy = data.aws_iam_policy_document.log_exporter.json
}

resource "aws_iam_role_policy_attachment" "log_exporter" {
  role       = aws_iam_role.log_exporter.name
  policy_arn = aws_iam_policy.log_exporter.arn
}

# S3 bucket
module "logs_export_bucket" {
  source = "../../modules/s3"

  name       = "${lower(var.name)}-log-export-${random_string.suffix.result}"
  versioning = false
  additional_policy_statements = [
    {
      sid       = "BucketACL"
      effect    = "Allow"
      actions   = ["s3:GetBucketAcl", "s3:PutBucketAcl"]
      resources = [module.logs_export_bucket.bucket_arn]
      principals = {
        type        = "Service"
        identifiers = ["logs.${var.aws_region}.amazonaws.com"]
      }
    },
    {
      sid       = "PutObject"
      effect    = "Allow"
      actions   = ["s3:PutObject", "s3:PutObjectAcl"]
      resources = ["${module.logs_export_bucket.bucket_arn}/*"]
      principals = {
        type        = "Service"
        identifiers = ["logs.${var.aws_region}.amazonaws.com"]
      }

      condition = {
        test     = "StringEquals"
        variable = "s3:x-amz-acl"

        values = [
          "bucket-owner-full-control"
        ]
      }
    }
  ]

  lifecycle_rules = [
    {
      id     = "logs"
      status = "Enabled"

      filter = {
        prefix = "${var.bucket_prefix}/"
      }

      transition = {
        days          = var.days_to_archive
        storage_class = var.archive_class
      }

      expiration = {
        days = var.days_to_expire
      }
    }
  ]
}

data "aws_iam_policy_document" "s3" {

  statement {
    sid       = "BucketACL"
    actions   = ["s3:GetBucketAcl", "s3:PutBucketAcl"]
    resources = [module.logs_export_bucket.bucket_arn]

    principals {
      type        = "Service"
      identifiers = ["logs.${var.aws_region}.amazonaws.com"]
    }
  }

  statement {
    sid       = "PutObject"
    actions   = ["s3:PutObject", "s3:PutObjectAcl"]
    resources = ["${module.logs_export_bucket.bucket_arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["logs.${var.aws_region}.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "s3:x-amz-acl"

      values = [
        "bucket-owner-full-control"
      ]
    }
  }
}

locals {
  enabled = module.this.enabled

  # Get all policies without a URL
  # { k = { "body": "https://", etc } }
  policies_with_body = {
    for k, v in var.policies :
    # merge them with existing data structure
    k => merge(v, {
      # append body_append to each body if one exists
      "body" = format(
        join("\n", [
          "# NOTE: source of policy is in the stack YAML",
          "",
          "%s",
        ]),
        lookup(v, "body", file("${path.module}/${lookup(v, "body_path")}")),
      )
    })
    if lookup(v, "body", null) != null || lookup(v, "body_path", null) != null
  }

  # Get all policies with a URL
  # { k = "https://" }
  policies_with_body_url = {
    for k, v in var.policies :
    k => try(
      format(v["body_url"], var.policy_version),
      v["body_url"],
    )
    if lookup(v, "body_url", null) != null
  }

  # After downloading the bodies from the URLs
  # { k = { "body" = "...", etc } }
  policies_with_body_url_downloaded = {
    for k, v in local.policies_with_body_url :
    # merge them with existing data structure
    k => merge(var.policies[k], {
      # append body_append to each body if one exists
      "body" = format(
        join("\n", [
          "# NOTE: source url of policy: %s",
          "",
          "%s",
        ]),
        v,
        data.http.default[k]["body"],
      )
    }) if local.enabled
  }

  # TODO: get local policies

  # Merge all the policies together and create policies from this object
  all_policies = merge(
    local.policies_with_body,
    local.policies_with_body_url_downloaded,
  )

  # keep the object keys consistent to avoid terraform errors
  policies = {
    for k, v in local.all_policies :
    k => merge(
      # remove optional keys
      {
        for vk, vv in v :
        vk => vv
        if !contains([
          "name",
          "body_append",
          "body_url",
          "body_path",
          "labels",
          "space_id",
        ], vk)
      },
      # these were previously set in the spacelift_policy resource and moved here
      # to avoid terraform errors around inconsistent object keys
      {
        name     = lookup(v, "name", title(join(" ", split("-", k))))
        labels   = lookup(v, "labels", var.labels)
        space_id = lookup(v, "space_id", var.space_id)
        body = lookup(v, "body_append", "") == "" ? v["body"] : format(
          join("\n", [
            "%s",
            "",
            "# NOTE: below is appended to the original policy",
            "",
            "%s",
          ]),
          v["body"],
          lookup(v, "body_append", "")
        )
      },
    )
  }
}

data "http" "default" {
  for_each = local.enabled ? local.policies_with_body_url : {}
  url      = each.value
}

resource "spacelift_policy" "default" {
  for_each = local.enabled ? local.policies : {}

  name     = lookup(each.value, "name")
  body     = lookup(each.value, "body")
  type     = upper(lookup(each.value, "type"))
  labels   = lookup(each.value, "labels")
  space_id = lookup(each.value, "space_id")
}

