provider "akamai" {
  edgerc = "../../common/testutils/edgerc"
}

resource "akamai_property" "test" {
  name        = "test_property"
  product_id  = "prd_0"
  group_id    = "grp_0"
  contract_id = "ctr_0"

  variables = "not empty"
}

data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Define the IAM role for DataBrew
data "aws_iam_policy_document" "assume_role" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["databrew.amazonaws.com"]
    }
  }
}

# Create the IAM role
resource "awscc_iam_role" "databrew_role" {
  role_name                   = "databrew-profile-job-role"
  assume_role_policy_document = data.aws_iam_policy_document.assume_role.json

  tags = [{
    key   = "Modified By"
    value = "AWSCC"
  }]
}

# Define the IAM policy for DataBrew job
data "aws_iam_policy_document" "databrew_policy" {
  statement {
    effect = "Allow"
    actions = [
      "s3:ListBucket",
      "s3:GetBucketLocation"
    ]
    resources = [
      "arn:aws:s3:::${awscc_s3_bucket.example.id}"
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "s3:GetObject",
      "s3:PutObject",
      "s3:DeleteObject"
    ]
    resources = [
      "arn:aws:s3:::${awscc_s3_bucket.example.id}/*"
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents"
    ]
    resources = [
      "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/databrew/*"
    ]
  }
}

# Attach the policy to the role
resource "awscc_iam_role_policy" "databrew_role_policy" {
  policy_document = data.aws_iam_policy_document.databrew_policy.json
  policy_name     = "databrew-job-policy"
  role_name       = awscc_iam_role.databrew_role.role_name
}

# Create example S3 bucket for outputs
resource "awscc_s3_bucket" "example" {
  bucket_name = "example-databrew-output-${data.aws_caller_identity.current.account_id}"
  tags = [{
    key   = "Modified By"
    value = "AWSCC"
  }]
}

# Upload a sample CSV file
resource "aws_s3_object" "sample" {
  bucket       = awscc_s3_bucket.example.id
  key          = "input/sample.csv"
  content      = "id,name,value\n1,test1,100\n2,test2,200"
  content_type = "text/csv"
}

# Create example dataset
resource "awscc_databrew_dataset" "example" {
  name = "example-dataset"
  input = {
    s3_input_definition = {
      bucket = awscc_s3_bucket.example.id
      key    = "input/sample.csv"
    }
  }
  format = "CSV"
}

# Create the DataBrew Job
resource "awscc_databrew_job" "example" {
  name     = "example-profile-job"
  role_arn = awscc_iam_role.databrew_role.arn
  type     = "PROFILE"

  dataset_name = awscc_databrew_dataset.example.name

  output_location = {
    bucket = awscc_s3_bucket.example.id
    key    = "output/profile-results/"
  }

  tags = [{
    key   = "Modified By"
    value = "AWSCC"
  }]
}

## The following resources setup a realtime ML datafeed.
resource "elasticstack_elasticsearch_index" "ml_datafeed_index" {
  name = "ml-datafeed-data"
  mappings = jsonencode({
    properties = {
      "@timestamp" = {
        type = "date"
      }
      value = {
        type = "double"
      }
      user = {
        type = "keyword"
      }
    }
  })
}

resource "elasticstack_elasticsearch_ml_anomaly_detection_job" "example" {
  job_id      = "example-anomaly-job"
  description = "Example anomaly detection job"

  analysis_config {
    bucket_span = "15m"
    detectors {
      function      = "mean"
      field_name    = "value"
      by_field_name = "user"
    }
  }

  data_description {
    time_field = "@timestamp"
  }
}

resource "elasticstack_elasticsearch_ml_datafeed" "example" {
  datafeed_id = "example-datafeed"
  job_id      = elasticstack_elasticsearch_ml_anomaly_detection_job.example.job_id
  indices     = [elasticstack_elasticsearch_index.ml_datafeed_index.name]

  query = jsonencode({
    bool = {
      must = [
        {
          range = {
            "@timestamp" = {
              gte = "now-7d"
            }
          }
        }
      ]
    }
  })
}

resource "elasticstack_elasticsearch_ml_datafeed_state" "example" {
  datafeed_id = elasticstack_elasticsearch_ml_datafeed.example.datafeed_id
  state       = "started"
  force       = false
}

## A non-realtime datafeed will automatically stop once all data has been processed.
## It's recommended to ignore changes to the `state` attribute via the resource lifecycle for such datafeeds.

resource "elasticstack_elasticsearch_ml_anomaly_detection_job" "non-realtime" {
  job_id      = "non-realtime-anomaly-job"
  description = "Test job for datafeed state testing with time range"
  analysis_config = {
    bucket_span = "1h"
    detectors = [{
      function             = "count"
      detector_description = "count"
    }]
  }
  data_description = {
    time_field  = "@timestamp"
    time_format = "epoch_ms"
  }
  analysis_limits = {
    model_memory_limit = "10mb"
  }
}

resource "elasticstack_elasticsearch_ml_job_state" "non-realtime" {
  job_id = elasticstack_elasticsearch_ml_anomaly_detection_job.non-realtime.job_id
  state  = "opened"

  lifecycle {
    ignore_changes = ["state"]
  }
}

resource "elasticstack_elasticsearch_ml_datafeed" "non-realtime" {
  datafeed_id = "non-realtime-datafeed"
  job_id      = elasticstack_elasticsearch_ml_anomaly_detection_job.non-realtime.job_id
  indices     = [elasticstack_elasticsearch_index.ml_datafeed_index.name]
  query = jsonencode({
    match_all = {}
  })
}

resource "elasticstack_elasticsearch_ml_datafeed_state" "non-realtime" {
  datafeed_id      = elasticstack_elasticsearch_ml_datafeed.non-realtime.datafeed_id
  state            = "started"
  start            = "2024-01-01T00:00:00Z"
  end              = "2024-01-02T00:00:00Z"
  datafeed_timeout = "60s"

  lifecycle {
    ignore_changes = ["state"]
  }
}

resource "google_network_services_http_route" "default" {
  name                   = "my-http-route-${local.name_suffix}"
  labels                 = {
