# tflint-ignore: terraform_unused_declarations
data "aws_appmesh_route" "test" {
  name                = aws_appmesh_route.test.name
  mesh_name           = aws_appmesh_route.test.mesh_name
  virtual_router_name = aws_appmesh_route.test.virtual_router_name
}

resource "aws_appmesh_route" "test" {
  name                = var.rName
  mesh_name           = aws_appmesh_mesh.test.id
  virtual_router_name = aws_appmesh_virtual_router.test.name

  spec {
    http_route {
      match {
        prefix = "/"
      }

      action {
        weighted_target {
          virtual_node = aws_appmesh_virtual_node.test1.name
          weight       = 100
        }
      }
    }
  }

  tags = var.resource_tags
}

resource "aws_appmesh_mesh" "test" {
  name = var.rName
}

resource "aws_appmesh_virtual_router" "test" {
  name      = var.rName
  mesh_name = aws_appmesh_mesh.test.id

  spec {
    listener {
      port_mapping {
        port     = 8080
        protocol = "http"
      }
    }
  }
}

resource "aws_appmesh_virtual_node" "test1" {
  name      = "${var.rName}-1"
  mesh_name = aws_appmesh_mesh.test.id

  spec {
    listener {
      port_mapping {
        port     = 8080
        protocol = "http"
      }
    }

    service_discovery {
      dns {
        hostname = "test1.simpleapp.local"
      }
    }
  }
}

resource "aws_appmesh_virtual_node" "test2" {
  name      = "${var.rName}-2"
  mesh_name = aws_appmesh_mesh.test.id

  spec {
    listener {
      port_mapping {
        port     = 8080
        protocol = "http"
      }
    }

    service_discovery {
      dns {
        hostname = "test2.simpleapp.local"
      }
    }
  }
}

variable "rName" {
  description = "Name for resource"
  type        = string
  nullable    = false
}

variable "resource_tags" {
  description = "Tags to set on resource. To specify no tags, set to `null`"
  # Not setting a default, so that this must explicitly be set to `null` to specify no tags
  type     = map(string)
  nullable = true
}

#-----------------------------------------------------------
# Global or/and default variables
#-----------------------------------------------------------
variable "name" {
  description = "Name to be used on all resources as prefix"
  default     = "TEST"
}

variable "environment" {
  description = "Environment for service"
  default     = "STAGE"
}

variable "tags" {
  description = "A list of tag blocks. Each element should have keys named key, value, etc."
  type        = map(string)
  default     = {}
}

#-----------------------------------------------------------
# SNS topic
#-----------------------------------------------------------
variable "enable_sns_topic" {
  description = "Enable SNS topic usage"
  default     = false
}

variable "sns_topic_name" {
  description = "The friendly name for the SNS topic. By default generated by Terraform."
  default     = ""
}

variable "sns_topic_name_prefix" {
  description = "(Optional) The friendly name for the SNS topic. Conflicts with sns_topic_name."
  default     = ""
}

variable "sns_topic_display_name" {
  description = "(Optional) The display name for the SNS topic"
  default     = ""
}

variable "sns_topic_delivery_policy" {
  description = "(Optional) The SNS delivery policy."
  default     = ""
}

variable "sns_topic_policy" {
  description = "(Optional) The fully-formed AWS policy as JSON. For more information about building AWS IAM policy documents with Terraform"
  default     = null
}

variable "sns_application_success_feedback_role_arn" {
  description = "(Optional) The IAM role permitted to receive success feedback for this topic"
  default     = null
}

variable "sns_application_success_feedback_sample_rate" {
  description = "(Optional) Percentage of success to sample"
  default     = null
}

variable "sns_application_failure_feedback_role_arn" {
  description = "(Optional) IAM role for failure feedback"
  default     = null
}

variable "sns_topic_http_success_feedback_role_arn" {
  description = "(Optional) The IAM role permitted to receive success feedback for this topic"
  default     = null
}

variable "sns_topic_http_success_feedback_sample_rate" {
  description = "(Optional) Percentage of success to sample"
  default     = null
}

variable "sns_topic_http_failure_feedback_role_arn" {
  description = "(Optional) IAM role for failure feedback"
  default     = null
}

variable "sns_topic_kms_master_key_id" {
  description = "(Optional) The ID of an AWS-managed customer master key (CMK) for Amazon SNS or a custom CMK."
  default     = null
}

variable "sns_topic_lambda_success_feedback_role_arn" {
  description = "(Optional) The IAM role permitted to receive success feedback for this topic"
  default     = null
}

variable "sns_topic_lambda_success_feedback_sample_rate" {
  description = "(Optional) Percentage of success to sample"
  default     = null
}

variable "sns_topic_lambda_failure_feedback_role_arn" {
  description = "(Optional) IAM role for failure feedback"
  default     = null
}

variable "sns_topic_sqs_success_feedback_role_arn" {
  description = "description"
  default     = null
}

variable "sns_topic_sqs_success_feedback_sample_rate" {
  description = "description"
  default     = null
}

variable "sns_topic_sqs_failure_feedback_role_arn" {
  description = "(Optional) IAM role for failure feedback"
  default     = null
}

#-----------------------------------------------------------
# SNS topic policy
#-----------------------------------------------------------
variable "enable_sns_topic_policy" {
  description = "Enable sns topic policy usage"
  default     = false
}

variable "sns_topic_policy_policy" {
  description = "(Required) The fully-formed AWS policy as JSON. For more information about building AWS IAM policy documents with Terraform, see the AWS IAM Policy Document Guide."
  default     = ""
}

variable "sns_topic_policy_topic_arn" {
  description = "The ARN of the SNS topic"
  default     = null
}

#-----------------------------------------------------------
# SNS topic subscription
#-----------------------------------------------------------
variable "enable_sns_topic_subscription" {
  description = "Enable sns topic subscription usage"
  default     = false
}

variable "sns_topic_subscription_topic_arn" {
  description = "(Required) The ARN of the SNS topic to subscribe to"
  default     = ""
}

variable "sns_topic_subscription_sns_protocol" {
  description = "The protocol to use. The possible values for this are: sqs, sms, lambda, application. (http or https are partially supported, see below) (email is option but unsupported)."
  default     = "sqs"
}

variable "sns_topic_subscription_sns_endpoints" {
  description = "The list of endpoints to send data to, the contents will vary with the protocol."
  default     = []
}

variable "sns_topic_subscription_confirmation_timeout_in_minutes" {
  description = "Set timeout in minutes. Integer indicating number of minutes to wait in retying mode for fetching subscription arn before marking it as failure. Only applicable for http and https protocols (default is 1 minute)."
  default     = 1
}

variable "sns_topic_subscription_endpoint_auto_confirms" {
  description = "Enable endpoint auto confirms. Boolean indicating whether the end point is capable of auto confirming subscription e.g., PagerDuty (default is false)"
  default     = false
}

variable "sns_topic_subscription_raw_message_delivery" {
  description = "Set raw message delivery.Boolean indicating whether or not to enable raw message delivery (the original message is directly passed, not wrapped in JSON with the original message in the message property) (default is false)."
  default     = false
}

variable "sns_topic_subscription_filter_policy" {
  description = "(Optional) JSON String with the filter policy that will be used in the subscription to filter messages seen by the target resource."
  default     = ""
}

variable "sns_topic_subscription_delivery_policy" {
  description = "(Optional) JSON String with the delivery policy (retries, backoff, etc.) that will be used in the subscription - this only applies to HTTP/S subscriptions. Refer to the SNS docs for more details."
  default     = ""
}

variable "sns_topic_application_success_feedback_role_arn" {
  description = "(Optional) The IAM role permitted to receive success feedback for this topic"
  default     = null
}

variable "sns_topic_application_success_feedback_sample_rate" {
  description = "(Optional) Percentage of success to sample"
  default     = null
}

variable "sns_topic_application_failure_feedback_role_arn" {
  description = "(Optional) IAM role for failure feedback"
  default     = null
}

#---------------------------------------------------
# SNS sms preferences
#---------------------------------------------------
variable "enable_sns_sms_preferences" {
  description = "Enable sns sms preferences usage"
  default     = false
}

variable "sns_sms_preferences_monthly_spend_limit" {
  description = "(Optional) The maximum amount in USD that you are willing to spend each month to send SMS messages."
  default     = null
}

variable "sns_sms_preferences_delivery_status_iam_role_arn" {
  description = "(Optional) The ARN of the IAM role that allows Amazon SNS to write logs about SMS deliveries in CloudWatch Logs."
  default     = null
}

variable "sns_sms_preferences_delivery_status_success_sampling_rate" {
  description = "(Optional) The percentage of successful SMS deliveries for which Amazon SNS will write logs in CloudWatch Logs. The value must be between 0 and 100."
  default     = null
}

variable "sns_sms_preferences_default_sender_id" {
  description = "(Optional) A string, such as your business brand, that is displayed as the sender on the receiving device."
  default     = null
}

variable "sns_sms_preferences_default_sms_type" {
  description = "(Optional) The type of SMS message that you will send by default. Possible values are: Promotional, Transactional"
  default     = null
}

variable "sns_sms_preferences_usage_report_s3_bucket" {
  description = "(Optional) The name of the Amazon S3 bucket to receive daily SMS usage reports from Amazon SNS."
  default     = null
}

#---------------------------------------------------
# SNS sms preferences
#---------------------------------------------------
variable "enable_sns_platform_application" {
  description = "Enable sns platform application usage"
  default     = false
}

variable "sns_platform_application_name" {
  description = "The friendly name for the SNS platform application"
  default     = ""
}

variable "sns_platform_application_platform" {
  description = "(Required) The platform that the app is registered with."
  default     = ""
}

variable "sns_platform_application_platform_credential" {
  description = "(Required) Application Platform credential. "
  default     = ""
}

variable "sns_platform_application_event_delivery_failure_topic_arn" {
  description = "(Optional) SNS Topic triggered when a delivery to any of the platform endpoints associated with your platform application encounters a permanent failure."
  default     = null
}

variable "sns_platform_application_event_endpoint_created_topic_arn" {
  description = "(Optional) SNS Topic triggered when a new platform endpoint is added to your platform application."
  default     = null
}

variable "sns_platform_application_event_endpoint_deleted_topic_arn" {
  description = "(Optional) SNS Topic triggered when an existing platform endpoint is deleted from your platform application."
