  jobspec = templatefile("${local.apps}/linkding.tpl",
    {
      datacenters        = local.datacenters
      linkding_subdomain = "linkding"
      domain             = local.domain

      linkding_image_version = var.linkding_image_version
      linkding_volumes_data  = var.linkding_volumes_data
  })
}

