  gateway_subnet_name     = "GatewaySubnet"
  gateway_subnet          = "10.0.0.0/24"
  cache_subnet_name       = "cache"
  cache_subnet            = "10.0.1.0/24"
  rendernodes_subnet_name = "rendernodes"
  rendernodes_subnet      = "10.0.4.0/22"
}

