variable "policy_name" {
  description = "Name of the Declarative Policy to Create"
  type        = string
}

variable "policy_type" {
  description = "Type of the Declarative Policy to Create"
  type        = string
}

variable "policy_description" {
  description = "Description of the Policy"
  type        = string
  default     = null
}

variable "policy_targets" {
  description = "OU to attach Policy to"
  type        = list(string)
  default     = []
}

variable "policy_json" {
  description = "JSON Document"
  type        = string
}

variable "ou_name_to_id" {}
variable "root_ou" {}

resource "aws_organizations_policy" "declarative_policy" {
  name        = var.policy_name
  type        = var.policy_type
  description = var.policy_description
  content     = var.policy_json
}

resource "aws_organizations_policy_attachment" "declarative_policy_attachment" {
  count     = length(var.policy_targets)
  policy_id = aws_organizations_policy.declarative_policy.id
  target_id = var.policy_targets[count.index] == "Root" ? var.root_ou : var.ou_name_to_id[var.policy_targets[count.index]]
}

variable "machines" {
  type        = list(string)
  description = "Machine names, corresponding to machine-NAME.yaml.tmpl files"
  default     = []
}

variable "cluster_name" {
  type        = string
  description = "Cluster name used as prefix for the machine names"
  default     = "terraform-flatcar"
}

variable "ssh_keys" {
  type        = list(string)
  default     = []
  description = "Additional SSH public keys for user 'core'."
}

variable "release_channel" {
  type        = string
  description = "Release channel"
  default     = "stable"

  validation {
    condition     = contains(["lts", "stable", "beta", "alpha"], var.release_channel)
    error_message = "release_channel must be lts, stable, beta, or alpha."
  }
}

variable "flavor_name" {
  type        = string
  description = "The OpenStack flavor to use (a.k.a the spec of the instance)"
  default     = "ds1G"
}

variable "flatcar_version" {
  type        = string
  description = "The Flatcar version associated to the release channel"
  default     = "current"
}

variable "user_name" {
  type        = string
  description = "OpenStack username"
}

variable "tenant_name" {
  type        = string
  description = "OpenStack tenant name"
}

variable "password" {
  type        = string
  description = "OpenStack password"
}

variable "auth_url" {
  type        = string
  description = "OpenStack authentication URL"
}

variable "region" {
  type        = string
  description = "OpenStack region"
  default     = "RegionOne"
}

variable "ssh" {
  type        = bool
  description = "Allow SSH connection from the outside"
  default     = false
}

variable "setup_replay_pipeline" {
  description = "Enable Replay Pipeline, True or False?"
  type        = bool
  default     = false

  validation {
    condition     = var.setup_replay_pipeline ? !var.batch_only : true
    error_message = "Replay pipeline can only be created when batch_only = false"
  }
}

variable "batch_only" {
  description = "Determines if the pipeline is batch only, True or False?"
  type        = bool
  default     = false
}

variable "replay_pipeline" {
  description = "Name for the Replay Pipeline"
  type        = string
  default     = ""
}

variable "step_function_execution_role_arn" {
  type        = string
  description = "The ARN of the step function execution role"
}

variable "dms_replication_task_arn" {
  description = "ARN of the replication task"
  type        = string
}

variable "replication_task_id" {
  description = "ID of the replication task"
  type        = string
}

variable "glue_unprocessed_raw_files_check_job" {
  description = "Name of job to ensure raw files have been processed"
  type        = string
  default     = ""
}

variable "glue_trigger_activation_job" {
  description = "Name of job to which activates/deactivates a glue trigger"
  type        = string
  default     = ""
}

variable "archive_job_trigger_name" {
  description = "Name of the trigger for a glue trigger"
  type        = string
  default     = ""
}

variable "glue_archive_job" {
  description = "Name of the glue job which archives the raw data"
  type        = string
  default     = ""
}

variable "glue_stop_glue_instance_job" {
