}

variable "glue_s3_max_attempts" {
  description = "The maximum number of attempts when making requests to S3"
  type        = number
}

variable "glue_s3_retry_min_wait_millis" {
  description = "The minimum wait duration in millis before a request to S3 is retried"
  type        = number
}

variable "glue_s3_retry_max_wait_millis" {
  description = "The maximum wait duration in millis before a request to S3 is retried"
  type        = number
}

variable "tags" {
  type        = map(string)
  default     = {}
  description = "(Optional) Key-value map of resource tags."
}

variable "domain" {
  type        = string
  default     = ""
  description = "Domain Name"
}

data "azurerm_kubernetes_cluster" "jok" {
  name                = "jok"
  resource_group_name = "jok-mpn-default"
}

resource "azureakscommand_invoke" "example" {
  resource_group_name = data.azurerm_kubernetes_cluster.jok.resource_group_name
  name                = data.azurerm_kubernetes_cluster.jok.name

  command = "kubectl cluster-info"

  lifecycle {
    postcondition {
      condition     = self.exit_code == 0
      error_message = "exit code invalid"
    }
  }
}

output "azureakscommand_invoke" {
  value = azureakscommand_invoke.example.output
}

