# This Terraform script will do:
# 1. Deploy an object store with one worker node
# 2. List all object stores
# 3. List all object store with filter
# 4. List all object store with limit
# 5. Fetch object store details using ext_id

# NOTE:
# 1. Before Deleting object store, make sure to delete buckets inside it
#    Currently, we are not supporting delete bucket API in terraform
# 2. Object store Update is used only to resume deployment of object store when it fails,
#    the state will be OBJECT_STORE_DEPLOYMENT_FAILED, update will resume the deployment

terraform {
  required_providers {
    nutanix = {
      source  = "nutanix/nutanix"
      version = "2.3.0"
    }
  }
}

#defining nutanix configuration
provider "nutanix" {
  username = var.nutanix_username
  password = var.nutanix_password
  endpoint = var.nutanix_endpoint
  port     = var.nutanix_port
  insecure = true
}

# subnet name to be used for object store
locals {
  subnetName = "objects.800"
}

# Fetching cluster and subnet details
data "nutanix_clusters_v2" "clusters" {}

data "nutanix_subnets_v2" "subnets" {
  filter = "name eq '${local.subnetName}'"
}

# Fetching cluster and subnet ext_id
locals {
  clusterExtId = [
    for cluster in data.nutanix_clusters_v2.clusters.cluster_entities :
    cluster.ext_id if cluster.config[0].cluster_function[0] != "PRISM_CENTRAL"
  ][0]
  subnetExtId = data.nutanix_subnets_v2.subnets.subnets[0].ext_id
}

# Deploying an object store
resource "nutanix_object_store_v2" "example" {
  name                     = "tf-example-os"
  description              = "terraform create object store example"
  deployment_version       = "5.1.1"
  domain                   = "msp.pc-idbc.nutanix.com"
  num_worker_nodes         = 1
  cluster_ext_id           = local.clusterExtId
  total_capacity_gib       = 20 * pow(1024, 3)
  public_network_reference = local.subnetExtId
  public_network_ips {
    ipv4 {
      value = "10.44.77.123"
    }
  }
  storage_network_reference = local.subnetExtId
  storage_network_dns_ip {
    ipv4 {
      value = "10.44.77.124"
    }
  }
  storage_network_vip {
    ipv4 {
      value = "10.44.77.125"
    }
  }
}

# Deploying Object Store in draft state
resource "nutanix_object_store_v2" "example-draft" {
  name                     = "tf-draft-os"
  description              = "terraform deploy object store draft example"
  deployment_version       = "5.1.1"
  domain                   = "msp.pc-idbc.nutanix.com"
  num_worker_nodes         = 1
  cluster_ext_id           = local.clusterExtId
  total_capacity_gib       = 20 * pow(1024, 3)
  public_network_reference = local.subnetExtId
  state                    = "UNDEPLOYED_OBJECT_STORE"
  public_network_ips {
    ipv4 {
      value = "10.44.77.126"
    }
  }
  storage_network_reference = local.subnetExtId
  storage_network_dns_ip {
    ipv4 {
      value = "10.44.77.127"
    }
  }
  storage_network_vip {
    ipv4 {
      value = "10.44.77.128"
    }
  }
}

# List all object stores
data "nutanix_object_stores_v2" "list" {
  depends_on = [nutanix_object_store_v2.example]
}

# List all object stores with filter
data "nutanix_object_stores_v2" "filter" {
  filter = "name eq '${nutanix_object_store_v2.example.name}'"
}

# List all object stores with limit
data "nutanix_object_stores_v2" "limit" {
  limit      = 1
  depends_on = [nutanix_object_store_v2.example]
}

# Fetch object store details using ext_id
data "nutanix_object_store_v2" "fetch" {
  ext_id = nutanix_object_store_v2.example.id
}

provider "vra" {
  url           = var.url
  refresh_token = var.refresh_token
  insecure      = var.insecure
}

data "vra_project" "this" {
  name = var.project_name
}

data "vra_catalog_item" "this" {
  name            = var.catalog_item_name
  expand_versions = true
}

resource "vra_deployment" "this" {
  name        = var.deployment_name
  description = "terraform test deployment"

  catalog_item_id      = data.vra_catalog_item.this.id
  catalog_item_version = var.catalog_item_version
  project_id           = data.vra_project.this.id

  inputs = {
    flavor = "small"
    image  = "centos"
    count  = 1
    flag   = false
    number = 10.0
    arrayProp = jsonencode(["foo", "bar", "where", "waldo"])
    objectProp = jsonencode({ "key1": "value1", "key2": [1, 2, 3, 4] })
  }

  timeouts {
    create = "30m"
    delete = "30m"
    update = "30m"
  }
}

output "resources" {
  description = "All the resources from a vRA deployment"
  value       = vra_deployment.this.resources
}

output "resource_properties_by_name" {
  description = "Properties of all resources by its name from a vRA deployment"
  value = {
    for rs in vra_deployment.this.resources :
    rs.name => jsondecode(rs.properties_json)
  }
}

output "resources_properties" {
  description = "Properties of all resources from a vRA deployment"
  value = [
    for rs in vra_deployment.this.resources :
    jsondecode(rs.properties_json)
  ]
}

output "addresses_by_name" {
  description = "Resource name and IP addresses of all machine type resources from a vRA deployment"
  value = {
    for props in sort(vra_deployment.this.resources.*.properties_json) :
    jsondecode(props).resourceName => jsondecode(props).address
    if jsondecode(props).componentType == "Cloud.Machine" || jsondecode(props).componentType == "Cloud.vSphere.Machine" || jsondecode(props).componentType == "Cloud.AWS.EC2.Instance" || jsondecode(props).componentType == "Cloud.GCP.Machine" || jsondecode(props).componentType == "Cloud.Azure.Machine"
  }
}

output "first_resource_address" {
  // Works for simple deployments with only one machine resource with count as 1.
  description = "IP address property of first resource in a vRA deployment"
  value       = jsondecode(sort(vra_deployment.this.resources.*.properties_json)[0]).address
}

output "all_resources_addresses" {
  // Gives address property from all resources of a deployment
  description = "IP address property of all resources from a vRA deployment"
  value = [
    for props in sort(vra_deployment.this.resources.*.properties_json) :
    jsondecode(props).address
  ]
}

terraform {
  required_providers {
    coder = {
      source  = "coder/coder"
    }
    docker = {
      source  = "kreuzwerker/docker"
    }
  }
}

locals {
  folder_name = try(element(split("/", data.coder_parameter.repo.value), length(split("/", data.coder_parameter.repo.value)) - 1), "")
  repo_owner_name = try(element(split("/", data.coder_parameter.repo.value), length(split("/", data.coder_parameter.repo.value)) - 2), "")
}

data "coder_workspace" "me" {
}

data "coder_workspace_owner" "me" {
}

data "coder_provisioner" "me" {
}

variable "socket" {
  type        = string
  description = <<-EOF
  The Unix socket that the Docker daemon listens on and how containers
  communicate with the Docker daemon.

  Either Unix or TCP
  e.g., unix:///var/run/docker.sock

  EOF
  default = "unix:///var/run/docker.sock"
}

provider "docker" {
  host = var.socket
}

provider "coder" {
}

data "coder_parameter" "image" {
  name        = "Container Image"
  type        = "string"
  description = "What container image and language do you want?"
  mutable     = true
  default     = "marktmilligan/python:latest"
  icon        = "https://www.docker.com/wp-content/uploads/2022/03/vertical-logo-monochromatic.png"

  option {
    name = "Node React"
    value = "marktmilligan/node:22.7.0"
    icon = "/icon/node.svg"
  }
  option {
    name = "Go"
    value = "marktmilligan/go:latest"
    icon = "/icon/go.svg"
  }
  option {
    name = "Python"
    value = "marktmilligan/python:latest"
    icon = "/icon/python.svg"
  }
  order       = 1
}

data "coder_parameter" "repo" {
  name        = "Source Code Repository"
  type        = "string"
  description = "What source code repository do you want to clone?"
  mutable     = true
  icon        = "/icon/git.svg"
  default     = "https://github.com/sharkymark/python_commissions"
  option {
    name = "Do not clone a repository"
    value = ""
    icon = "/emojis/274c.png"
  }
  option {
    name = "Node React Hello, World"
    value = "https://github.com/sharkymark/coder-react"
    icon = "/icon/node.svg"
  }
  option {
    name = "Coder CDE OSS Go project"
    value = "https://github.com/coder/coder"
    icon = "/icon/coder.svg"
  }
  option {
    name = "Python CLI app for calculating sales commissions"
    value = "https://github.com/sharkymark/python_commissions"
    icon = "/icon/python.svg"
  }
  order       = 2
}

module "dotfiles" {
  count    = data.coder_workspace.me.start_count
  source   = "registry.coder.com/modules/dotfiles/coder"
  agent_id = coder_agent.dev.id
}

module "vscode-web" {
  count          = data.coder_workspace.me.start_count
  source         = "registry.coder.com/modules/vscode-web/coder"
  agent_id       = coder_agent.dev.id
  extensions     = ["github.copilot"]
  folder         = "/home/coder"
  accept_license = true
}

module "git-clone" {
  count    = data.coder_workspace.me.start_count
  source   = "registry.coder.com/modules/git-clone/coder"
  version  = "1.0.18"
  agent_id = coder_agent.dev.id
  url      = "${data.coder_parameter.repo.value}"
}

module "coder-login" {
  count    = data.coder_workspace.me.start_count
  source   = "registry.coder.com/modules/coder-login/coder"
  agent_id = coder_agent.dev.id
}

module "git-config" {
  count    = data.coder_workspace.me.start_count
  source   = "registry.coder.com/modules/git-config/coder"
  agent_id = coder_agent.dev.id
}

resource "coder_agent" "dev" {
  arch           = data.coder_provisioner.me.arch
  os             = "linux"

  # The following metadata blocks are optional. They are used to display
  # information about your workspace in the dashboard. You can remove them
  # if you don't want to display any information.
  # For basic resources, you can use the `coder stat` command.
  # If you need more control, you can write your own script.

  metadata {
    display_name = "CPU Usage"
    key          = "0_cpu_usage"
    script       = "coder stat cpu"
    interval     = 10
    timeout      = 1
  }

  metadata {
    display_name = "RAM Usage"
    key          = "1_ram_usage"
    script       = "coder stat mem"
    interval     = 10
    timeout      = 1
  }

  metadata {
    display_name = "CPU Usage (Host)"
    key          = "4_cpu_usage_host"
    script       = "coder stat cpu --host"
    interval     = 10
    timeout      = 1
  }

  metadata {
    display_name = "Memory Usage (Host)"
    key          = "5_mem_usage_host"
    script       = "coder stat mem --host"
    interval     = 10
    timeout      = 1
  }

  metadata {
    display_name = "Home Disk"
    key          = "3_home_disk"
    script       = "coder stat disk --path $${HOME}"
    interval     = 60
    timeout      = 1
  }

  display_apps {
    vscode = true
    vscode_insiders = false
    ssh_helper = false
    port_forwarding_helper = true
    web_terminal = true
  }

  startup_script_behavior = "non-blocking"
  connection_timeout = 300
  startup_script  = <<EOT
  #!/bin/sh

  EOT
}

resource "docker_container" "workspace" {
  count = data.coder_workspace.me.start_count
  image = data.coder_parameter.image.value
  # Uses lower() to avoid Docker restriction on container names.
  name     = "coder-${data.coder_workspace_owner.me.name}-${lower(data.coder_workspace.me.name)}"
  hostname = lower(data.coder_workspace.me.name)
  dns      = ["1.1.1.1"]

  # Use the docker gateway if the access URL is 127.0.0.1
  #entrypoint = ["sh", "-c", replace(coder_agent.dev.init_script, "127.0.0.1", "host.docker.internal")]

  # Use the docker gateway if the access URL is 127.0.0.1
  command = [
    "sh", "-c",
    <<EOT
    trap '[ $? -ne 0 ] && echo === Agent script exited with non-zero code. Sleeping infinitely to preserve logs... && sleep infinity' EXIT
    ${replace(coder_agent.dev.init_script, "/localhost|127\\.0\\.0\\.1/", "host.docker.internal")}
    EOT
  ]

  env        = ["CODER_AGENT_TOKEN=${coder_agent.dev.token}"]
  volumes {
    container_path = "/home/coder/"
    volume_name    = docker_volume.coder_volume.name
    read_only      = false
  }
  host {
    host = "host.docker.internal"
    ip   = "host-gateway"
  }

}

resource "docker_volume" "coder_volume" {
  name = "coder-${data.coder_workspace_owner.me.name}-${data.coder_workspace.me.name}"
}

resource "coder_metadata" "workspace_info" {
  count       = data.coder_workspace.me.start_count
  resource_id = docker_container.workspace[0].id
  item {
    key   = "image"
    value = "${data.coder_parameter.image.value}"
  }
  item {
    key   = "repo cloned"
    value = "${local.repo_owner_name}/${local.folder_name}"
  }
}

terraform {
  required_providers {
    nutanix = {
      source  = "nutanix/nutanix"
      version = "2.1.0"
    }
  }
}

#defining nutanix configuration
provider "nutanix" {
  username = var.nutanix_username
  password = var.nutanix_password
  endpoint = var.nutanix_endpoint
  port     = 9440
  insecure = true
}

#################### Example 1: Restore VM ####################
# Restore a protected virtual machine on remote site
# This example demonstrates how to restore a protected virtual machine on remote site.
# steps:
# 1. Define the provider for the remote site
# 2. List domain Managers, Clusters for the local and remote sites
# 3. Create a category and a protection policy, on the local site
# 4. Create a virtual machine and associate it with the protection policy, on local site
# 5. Restore the virtual machine on the remote site

# define another alias for the provider, this time for the remote PC
provider "nutanix" {
  alias    = "remote"
  username = var.nutanix_remote_username
  password = var.nutanix_remote_password
  endpoint = var.nutanix_remote_endpoint
  insecure = true
  port     = 9440
}

# List domain Managers
data "nutanix_pcs_v2" "pcs-list" {
  provider = nutanix
}

# list Clusters
data "nutanix_clusters_v2" "clusters" {
  provider = nutanix
}

# remote pc list
data "nutanix_pcs_v2" "pcs-list-remote" {
  provider = nutanix.remote
}

# remote cluster list
data "nutanix_clusters_v2" "clusters-remote" {
  provider = nutanix.remote
}

locals {
  clusterExtId = [
    for cluster in data.nutanix_clusters_v2.clusters.cluster_entities :
    cluster.ext_id if cluster.config[0].cluster_function[0] != "PRISM_CENTRAL"
  ][
  0
  ]
  localPcExtId       = data.nutanix_pcs_v2.pcs-list.pcs[0].ext_id
  remoteClusterExtId = [
    for cluster in data.nutanix_clusters_v2.clusters-remote.cluster_entities :
    cluster.ext_id if cluster.config[0].cluster_function[0] != "PRISM_CENTRAL"
  ][
  0
  ]
  remotePcExtId = data.nutanix_pcs_v2.pcs-list-remote.pcs[0].ext_id
}

# Create Category
resource "nutanix_category_v2" "example" {
  provider    = nutanix
  key         = "tf-example-category-pp-restore-vm"
  value       = "tf_example_category_pp_restore_vm"
  description = "category for protection policy and protected vm"
}

resource "nutanix_protection_policy_v2" "pp-vm" {
  provider    = nutanix
  name        = "pp_example_1"
  description = "protection policy for restore vm"

  replication_configurations {
    source_location_label = "source"
    remote_location_label = "target"
    schedule {
      recovery_point_objective_time_seconds         = 60
      recovery_point_type                           = "CRASH_CONSISTENT"
      sync_replication_auto_suspend_timeout_seconds = 300
      retention {
        auto_rollup_retention {
          local {
            snapshot_interval_type = "DAILY"
            frequency              = 1
          }
          remote {
            snapshot_interval_type = "DAILY"
            frequency              = 1
          }
        }
      }
    }
  }
  replication_configurations {
    source_location_label = "target"
    remote_location_label = "source"
    schedule {
      recovery_point_objective_time_seconds         = 60
      recovery_point_type                           = "CRASH_CONSISTENT"
      sync_replication_auto_suspend_timeout_seconds = 300
      retention {
        auto_rollup_retention {
          local {
            snapshot_interval_type = "DAILY"
            frequency              = 1
          }
          remote {
            snapshot_interval_type = "DAILY"
            frequency              = 1
          }
        }
      }
    }
  }

  replication_locations {
    domain_manager_ext_id = local.localPcExtId
    label                 = "source"
    is_primary            = true
  }
  replication_locations {
    domain_manager_ext_id = local.remotePcExtId
    label                 = "target"
    is_primary            = false
  }

  category_ids = [nutanix_category_v2.example.id]
}

resource "nutanix_virtual_machine_v2" "vm" {
  name                 = "tf-vm-example-restore"
  description          = "virtual machine for restore"
  num_cores_per_socket = 1
  num_sockets          = 1
  cluster {
    ext_id = local.clusterExtId
  }
  categories {
    ext_id = nutanix_category_v2.example.id
  }
  power_state = "OFF"
  depends_on = [nutanix_protection_policy_v2.pp-vm]
  provisioner "local-exec" {
    # sleep 5 min to wait for the vm to be protected
    command = "sleep 300"
    when    = create
  }
}

resource "nutanix_restore_protected_resource_v2" "rp-vm" {
  provider       = nutanix.remote
  ext_id         = nutanix_virtual_machine_v2.vm.id
  cluster_ext_id = local.remoteClusterExtId
}

#################### Example 2: Restore Volume Group ####################
# Restore a protected volume group on remote site
# This example demonstrates how to restore a protected volume group on remote site.
