locals {
  default_arguments = {
    "--job-language"            = var.job_language
    "--job-bookmark-option"     = var.bookmark_options[var.bookmark]
    "--TempDir"                 = var.temp_dir
    "--checkpoint.location"     = var.checkpoint_dir
    "--spark-event-logs-path"   = var.spark_event_logs
    "--enable-glue-datacatalog" = "true"
    "--enable-job-insights"     = "true"
    "--enable-spark-ui"         = var.enable_spark_ui
  }

  tags = var.tags

}

resource "aws_glue_job" "glue_job" {
  count = var.create_job ? 1 : 0

  name        = var.name
  role_arn    = var.create_role ? join("", aws_iam_role.glue-service-role.*.arn) : var.role_arn
  connections = var.connections
  # max_capacity         = var.dpu
  description            = var.description
  glue_version           = var.glue_version
  max_retries            = var.max_retries
  security_configuration = var.create_security_configuration ? join("", aws_glue_security_configuration.sec_cfg.*.id) : var.security_configuration
  worker_type            = var.worker_type
  number_of_workers      = var.number_of_workers
  execution_class        = var.execution_class
  maintenance_window     = var.maintenance_window
  tags                   = local.tags

  command {
    script_location = var.script_location
    name            = var.command_type
  }

  # https://docs.aws.amazon.com/glue/latest/dg/aws-glue-programming-etl-glue-arguments.html
  default_arguments = merge(local.default_arguments, var.arguments)

  execution_property {
    max_concurrent_runs = var.max_concurrent
  }

  dynamic "notification_property" { ##minutes
    for_each = var.notify_delay_after == null ? [] : [1]

    content {
      notify_delay_after = var.notify_delay_after
    }
  }
}

### Glue Job Service Role
resource "aws_iam_role" "glue-service-role" {
  count = var.create_role && var.create_job ? 1 : 0
  name  = "${var.name}-glue-role"
  tags  = local.tags
  path  = "/"

  assume_role_policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Action": "sts:AssumeRole",
            "Principal": {
               "Service": "glue.amazonaws.com"
            },
            "Effect": "Allow",
            "Sid": ""
        }
    ]
}
EOF
}

data "aws_iam_policy_document" "extra-policy-document" {
  #checkov:skip=CKV_AWS_356: "Ensure no IAM policies documents allow "*" as a statement's resource for restrictable actions. TO DO Will be addressed as part of https://dsdmoj.atlassian.net/browse/DPR2-1083"
  #checkov:skip=CKV_AWS_109: "Ensure IAM policies does not allow permissions management / resource exposure without constraints"
  #checkov:skip=CKV_AWS_111: "Ensure IAM policies does not allow write access without constraints"
  #checkov:skip=CKV_AWS_110: "Ensure IAM policies does not allow privilege escalation"

  statement {
    actions = [
      "s3:PutObject",
      "s3:ListBucket",
      "s3:GetObjectAcl",
      "s3:GetObject",
      "s3:GetBucketLocation",
      "s3:DeleteObject",
    ]
    resources = [
      "arn:aws:s3:::${var.project_id}-*/*",
      "arn:aws:s3:::${var.project_id}-*",
    ]
  }
  # https://docs.aws.amazon.com/glue/latest/dg/monitor-continuous-logging-enable.html#monitor-continuous-logging-encrypt-log-data
  statement {
    actions = [
      "logs:PutLogEvents",
      "logs:CreateLogStream",
      "logs:CreateLogGroup",
      "logs:AssociateKmsKey",
    ]
    resources = [
      "arn:aws:logs:*:*:/aws-glue/*"
    ]
  }
  statement {
    actions = [
      "sqs:*", # Needs Fixing
      "iam:ListRolePolicies",
      "iam:GetRolePolicy",
      "iam:GetRole",
      "glue:*",
      "cloudwatch:PutMetricData",
    ]
    resources = [
      "*"
    ]
  }
  statement {
    actions = [
      "dms:StopReplicationTask",
      "dms:ModifyReplicationTask",
      "dms:DescribeTableStatistics",
      "dms:DescribeReplicationTasks",
    ]
    resources = [
      "arn:aws:dms:${var.region}:${var.account}:*:*"
    ]
  }
  statement {
    actions = [
      "secretsmanager:GetSecretValue",
      "secretsmanager:DescribeSecret",
    ]
    resources = concat(var.additional_secret_arns, [
      "arn:aws:secretsmanager:${var.region}:${var.account}:secret:external/${var.project_id}-dps-*",
      "arn:aws:secretsmanager:${var.region}:${var.account}:secret:${var.project_id}-redshift-secret-*",
    ])
  }
  statement {
    actions = [
      "kms:ReEncrypt*",
      "kms:GenerateDataKey*",
      "kms:Encrypt*",
      "kms:DescribeKey",
      "kms:Decrypt*",
    ]
    resources = [
      "arn:aws:kms:*:${var.account}:key/*"
    ]
  }
  statement {
    actions = [
      "dynamodb:Update*",
      "dynamodb:Scan",
      "dynamodb:Query",
      "dynamodb:PutItem",
      "dynamodb:Get*",
      "dynamodb:DescribeTable",
      "dynamodb:DescribeStream",
      "dynamodb:Delete*",
      "dynamodb:CreateTable",
      "dynamodb:BatchWrite*",
      "dynamodb:BatchGet*",
    ]
    resources = [
      "arn:aws:dynamodb:${var.region}:${var.account}:table/dpr-*"
    ]
  }
}

resource "aws_iam_policy" "additional-policy" {
  count = var.create_role && var.create_job ? 1 : 0

  name        = "${var.name}-policy"
  description = "Extra Policy for AWS Glue Job"
  policy      = data.aws_iam_policy_document.extra-policy-document.json
  tags        = var.tags
}

resource "aws_iam_role_policy_attachment" "glue_policies" {
  for_each = var.create_role ? toset([
    try("arn:aws:iam::${var.account}:policy/${aws_iam_policy.additional-policy[0].name}", null),
    "arn:aws:iam::aws:policy/service-role/AWSGlueServiceRole"
  ]) : []

  role       = var.create_job ? join("", aws_iam_role.glue-service-role.*.name) : var.role_name
  policy_arn = each.value
}

resource "aws_cloudwatch_log_group" "job" {
  #checkov:skip=CKV_AWS_158: "Ensure that CloudWatch Log Group is encrypted by KMS, Skipping for Timebeing in view of Cost Savings”

  count = var.create_job ? 1 : 0

  name              = "/aws-glue/jobs/${var.name}"
  retention_in_days = var.log_group_retention_in_days
  tags              = var.tags
}

resource "aws_cloudwatch_log_group" "sec_config" {
  #checkov:skip=CKV_AWS_158: "Ensure that CloudWatch Log Group is encrypted by KMS, Skipping for Timebeing in view of Cost Savings”

  count = var.create_job ? 1 : 0

  name              = "/aws-glue/jobs/${var.short_name}-sec-config"
  retention_in_days = var.log_group_retention_in_days
  tags              = var.tags
}

resource "aws_cloudwatch_log_group" "sec_config_error" {
  #checkov:skip=CKV_AWS_158: "Ensure that CloudWatch Log Group is encrypted by KMS, Skipping for Timebeing in view of Cost Savings”

  count = var.create_job ? 1 : 0

  name              = "/aws-glue/jobs/${var.short_name}-sec-config-role/${var.name}-glue-role/error"
  retention_in_days = var.log_group_retention_in_days
  tags              = var.tags
}

resource "aws_cloudwatch_log_group" "sec_config_output" {
  #checkov:skip=CKV_AWS_158: "Ensure that CloudWatch Log Group is encrypted by KMS, Skipping for Timebeing in view of Cost Savings”

  count = var.create_job ? 1 : 0

  name              = "/aws-glue/jobs/${var.short_name}-sec-config-role/${var.name}-glue-role/output"
  retention_in_days = var.log_group_retention_in_days
  tags              = var.tags
}

resource "aws_glue_security_configuration" "sec_cfg" {
  #checkov:skip=CKV_AWS_99: "Ensure Glue Security Configuration Encryption is enabled. TODO Will be addressed as part of https://dsdmoj.atlassian.net/browse/DPR2-1083"

  count = var.create_security_configuration && var.create_job ? 1 : 0
  name  = "${var.short_name}-sec-config"

  encryption_configuration {
    cloudwatch_encryption {
      cloudwatch_encryption_mode = "DISABLED"
    }

    job_bookmarks_encryption {
      job_bookmarks_encryption_mode = "DISABLED"
    }

    s3_encryption {
      kms_key_arn        = var.aws_kms_key
      s3_encryption_mode = "SSE-KMS"
    }
  }
}

# ---------------------------------------------------------------------------------------------------------------------
# DEPLOY SERVICE ACCOUNTS
# ---------------------------------------------------------------------------------------------------------------------

##### setup bastion host service account to be attached to compute engine VM #####
resource "google_service_account" "service-account-bastion-host" {
  project      = var.project
  account_id   = var.account_id_bastion_host
  display_name = var.display_name_bastion_host
  description  = var.description_bastion_host
}

# hard-coded as this is specific to cloud composer enablement
locals {
  bastion_service_account_roles = concat(var.bastion_service_account_roles_to_add, [
    "roles/composer.user",
    "roles/container.developer"
  ])
}

resource "google_project_iam_binding" "bastion-host-entry" {
  project  = var.project
  for_each = toset(local.bastion_service_account_roles)
  role     = each.value

  members = [
    "serviceAccount:${google_service_account.service-account-bastion-host.email}",
  ]
}

##### setup identity access proxy service account to be attached to be used by end user to ssh into compute engine VM #####
#TODO: build conditions for all the iam policy bindings to be specific to this custom setup

# create custom role to set compute metadata to enable IAP ssh tunneling into the bastion host VM
resource "google_project_iam_custom_role" "set-compute-metadata" {
  project     = var.project
  role_id     = var.compute_role_id
  title       = var.compute_role_title
  description = var.compute_role_desc
  permissions = var.custom_compute_permissions
}

# download private key after terraform creates
resource "google_service_account" "service-account-iap-ssh" {
  project      = var.project
  account_id   = var.account_id_iap_ssh
  display_name = var.display_name_iap_ssh
  description  = var.description_iap_ssh
}

# hard-coded as this is specific to identity aware proxy ssh enablement
locals {
  ssh_service_account_roles = concat(var.ssh_service_account_roles_to_add, [
    "roles/iap.tunnelResourceAccessor",
    "roles/compute.viewer",
  ])
}

resource "google_project_iam_binding" "ssh-iap-compute-policy" {
  project  = var.project
  for_each = toset(local.ssh_service_account_roles)
  role     = each.value

  members = [
    "serviceAccount:${google_service_account.service-account-iap-ssh.email}",
  ]
}

resource "google_project_iam_binding" "ssh-iap-set-compute-metadata" {
  project = var.project
  role    = google_project_iam_custom_role.set-compute-metadata.id

  members = [
    "serviceAccount:${google_service_account.service-account-iap-ssh.email}",
  ]
}

resource "google_service_account_iam_binding" "bastion-host-service-account-user" {
  service_account_id = google_service_account.service-account-bastion-host.name
  role               = "roles/iam.serviceAccountUser"

  members = [
    "serviceAccount:${google_service_account.service-account-iap-ssh.email}",
  ]
}

##### setup service account to ensure composer environment is setup correctly #####
resource "google_service_account" "service-account-composer" {
  project      = var.project
  account_id   = var.account_id_composer
  display_name = var.display_name_composer
  description  = var.description_composer
}

resource "google_project_iam_member" "composer-worker" {
  project = var.project
  role    = "roles/composer.worker" # hard-coded as this is specific to cloud composer enablement
  member  = "serviceAccount:${google_service_account.service-account-composer.email}"
}

resource "google_vertex_ai_feature_group" "feature_group" {
  name = "example_feature_group-${local.name_suffix}"
  description = "A sample feature group"
  region = "us-central1"
  labels = {
      label-one = "value-one"
  }
  big_query {
    big_query_source {
        # The source table must have a column named 'feature_timestamp' of type TIMESTAMP.
        input_uri = "bq://${google_bigquery_table.sample_table.project}.${google_bigquery_table.sample_table.dataset_id}.${google_bigquery_table.sample_table.table_id}"
    }
    entity_id_columns = ["feature_id"]
  }
}

resource "google_bigquery_dataset" "sample_dataset" {
  dataset_id                  = "job_load-${local.name_suffix}_dataset"
  friendly_name               = "test"
  description                 = "This is a test description"
  location                    = "US"
}

resource "google_bigquery_table" "sample_table" {
  deletion_protection = false
  dataset_id = google_bigquery_dataset.sample_dataset.dataset_id
  table_id   = "job_load-${local.name_suffix}_table"

  schema = <<EOF
[
    {
        "name": "feature_id",
        "type": "STRING",
        "mode": "NULLABLE"
    },
    {
        "name": "feature_timestamp",
        "type": "TIMESTAMP",
        "mode": "NULLABLE"
    }
]
EOF
}

