# create virtual machine with cdrom
resource "nutanix_virtual_machine_v2" "example-7" {
  name                 = "example-vm-7"
  num_cores_per_socket = 1
  num_sockets          = 1
  cluster {
    ext_id = local.cluster_ext_id
  }
  boot_config {
    legacy_boot {
      boot_order = ["CDROM", "DISK", "NETWORK"]
    }
