locals {
  ctx = {
    for k, v in var.context : k => {
      for kk, vv in v : "${local.ctx_p}${k}:${kk}" => vv
    }
  }
  ctx_p = "$"
  md5_keys = {
    for k, v in random_id.md5_keys
    : k => v.b64_url
  }
  network = lookup(local.ctx.networks, var.network, var.network)
  peer_gateways_external = {
    for k, v in var.peer_gateways : k => v.external if v.external != null
  }
  peer_gateways_gcp = {
    for k, v in var.peer_gateways :
    k => lookup(local.ctx.vpn_gateways, v.gcp, v.gcp) if v.gcp != null
  }
  project_id = lookup(
    local.ctx.project_ids, var.project_id, var.project_id
  )
  region = lookup(
    local.ctx.locations, var.region, var.region
  )
  router = (
    var.router_config.create
    ? try(google_compute_router.router[0].name, null)
    : lookup(local.ctx.routers, var.router_config.name, var.router_config.name)
  )
  vpn_gateway = (
    var.vpn_gateway_create != null
    ? try(google_compute_ha_vpn_gateway.ha_gateway[0].self_link, null)
    : lookup(local.ctx.vpn_gateways, var.vpn_gateway, var.vpn_gateway)
  )
  secret = random_id.secret.b64_url
}

resource "google_compute_ha_vpn_gateway" "ha_gateway" {
  count       = var.vpn_gateway_create != null ? 1 : 0
  name        = var.name
  description = var.vpn_gateway_create.description
  project     = local.project_id
  region      = local.region
  network     = local.network
  stack_type  = var.vpn_gateway_create.ipv6 ? "IPV4_IPV6" : "IPV4_ONLY"
}

resource "google_compute_external_vpn_gateway" "external_gateway" {
  for_each        = local.peer_gateways_external
  name            = each.value.name != null ? each.value.name : "${var.name}-${each.key}"
  project         = local.project_id
  redundancy_type = each.value.redundancy_type
  description     = each.value.description
  dynamic "interface" {
    for_each = each.value.interfaces
    content {
      id         = interface.key
      ip_address = lookup(local.ctx.addresses, interface.value, interface.value)
    }
  }
}

resource "google_compute_router" "router" {
  count   = var.router_config.create ? 1 : 0
  name    = coalesce(var.router_config.name, "vpn-${var.name}")
  project = local.project_id
  region  = local.region
  network = local.network
  bgp {
    advertise_mode = (
      var.router_config.custom_advertise != null
      ? "CUSTOM"
      : "DEFAULT"
    )
    advertised_groups = (
      try(var.router_config.custom_advertise.all_subnets, false)
      ? ["ALL_SUBNETS"]
      : []
    )
    dynamic "advertised_ip_ranges" {
      for_each = try(var.router_config.custom_advertise.ip_ranges, {})
      iterator = range
      content {
        range       = range.key
        description = range.value
      }
    }
    keepalive_interval = try(var.router_config.keepalive, null)
    asn                = var.router_config.asn
  }
}

resource "google_compute_router_peer" "bgp_peer" {
  for_each                  = var.tunnels
  region                    = local.region
  project                   = local.project_id
  name                      = each.value.bgp_peer.name != null ? each.value.bgp_peer.name : "${var.name}-${each.key}"
  router                    = coalesce(each.value.router, local.router)
  peer_ip_address           = each.value.bgp_peer.address
  peer_asn                  = each.value.bgp_peer.asn
  advertised_route_priority = each.value.bgp_peer.route_priority
  advertise_mode = (
    try(each.value.bgp_peer.custom_advertise, null) != null
    ? "CUSTOM"
    : "DEFAULT"
  )
  advertised_groups = try(each.value.bgp_peer.custom_advertise.all_subnets, false) ? ["ALL_SUBNETS"] : []
  dynamic "advertised_ip_ranges" {
    for_each = try(each.value.bgp_peer.custom_advertise.ip_ranges, {})
    iterator = range
    content {
      range       = range.key
      description = range.value
    }
  }
  dynamic "custom_learned_ip_ranges" {
    for_each = try(each.value.bgp_peer.custom_learned_ip_ranges.ip_ranges, {})
    iterator = range
    content {
      range = range.value
    }
  }
  custom_learned_route_priority = try(
    each.value.bgp_peer.custom_learned_ip_ranges.route_priority,
    null
  )
  dynamic "md5_authentication_key" {
    for_each = each.value.bgp_peer.md5_authentication_key != null ? toset([each.value.bgp_peer.md5_authentication_key]) : []
    content {
      name = md5_authentication_key.value.name
      key  = coalesce(md5_authentication_key.value.key, local.md5_keys[each.key])
    }
  }
  enable_ipv6                        = try(each.value.bgp_peer.ipv6, null) == null ? false : true
  interface                          = google_compute_router_interface.router_interface[each.key].name
  ipv6_nexthop_address               = try(each.value.bgp_peer.ipv6.nexthop_address, null)
  peer_ipv6_nexthop_address          = try(each.value.bgp_peer.ipv6.peer_nexthop_address, null)
  zero_custom_learned_route_priority = try(each.value.bgp_peer.custom_learned_ip_ranges.route_priority, 1000) == 0 ? true : false
}

resource "google_compute_router_interface" "router_interface" {
  for_each = var.tunnels
  project  = local.project_id
  region   = local.region
  name = (
    each.value.peer_router_interface_name != null
    ? each.value.peer_router_interface_name :
    "${var.name}-${each.key}"
  )
  router = local.router
  # FIXME: can bgp_session_range be null?
  ip_range   = each.value.bgp_session_range == "" ? null : each.value.bgp_session_range
  vpn_tunnel = google_compute_vpn_tunnel.tunnels[each.key].name
}

resource "google_compute_vpn_tunnel" "tunnels" {
  for_each = var.tunnels
  project  = local.project_id
  region   = local.region
  name     = each.value.name != null ? each.value.name : "${var.name}-${each.key}"
  router   = local.router
  peer_external_gateway = try(
    google_compute_external_vpn_gateway.external_gateway[each.value.peer_gateway].id,
    null
  )
  peer_external_gateway_interface = each.value.peer_external_gateway_interface
  peer_gcp_gateway = lookup(
    local.peer_gateways_gcp, each.value.peer_gateway, null
  )
  vpn_gateway_interface = each.value.vpn_gateway_interface
  ike_version           = each.value.ike_version
  shared_secret         = coalesce(each.value.shared_secret, local.secret)
  vpn_gateway           = local.vpn_gateway
}

resource "random_id" "secret" {
  byte_length = 8
}

resource "random_id" "md5_keys" {
  for_each    = var.tunnels
  byte_length = 12
}

resource "aws_glue_ml_transform" "this" {
  name     = var.name
  role_arn = var.role_arn

  dynamic "input_record_tables" {
    for_each = var.input_record_tables
    content {
      database_name   = input_record_tables.value.database_name
      table_name      = input_record_tables.value.table_name
      catalog_id      = input_record_tables.value.catalog_id
      connection_name = input_record_tables.value.connection_name
    }
  }

  parameters {
    transform_type = var.parameters.transform_type

    dynamic "find_matches_parameters" {
      for_each = var.parameters.find_matches_parameters != null ? [var.parameters.find_matches_parameters] : []
      content {
        accuracy_cost_trade_off    = find_matches_parameters.value.accuracy_cost_trade_off
        enforce_provided_labels    = find_matches_parameters.value.enforce_provided_labels
        precision_recall_trade_off = find_matches_parameters.value.precision_recall_trade_off
        primary_key_column_name    = find_matches_parameters.value.primary_key_column_name
      }
    }
  }

  description       = var.description
  glue_version      = var.glue_version
  max_capacity      = var.max_capacity
  max_retries       = var.max_retries
  tags              = var.tags
  timeout           = var.timeout
  worker_type       = var.worker_type
  number_of_workers = var.number_of_workers
}

#-----------------------------------------------------------
# Global or/and default variables
#-----------------------------------------------------------
variable "name" {
  description = "Name to be used on all resources as prefix"
  default     = "this"
}

variable "environment" {
  description = "Environment for service"
  default     = "test"
}

variable "tags" {
  description = "Add additional tags"
  default     = {}
}

#-----------------------------------------------------------
# Azure active directory domain service
#-----------------------------------------------------------
variable "enable_active_directory_domain_service" {
  description = "Enable active directory domain service usage"
  default     = false
}

variable "active_directory_domain_service_name" {
  description = "The display name for your managed Active Directory Domain Service resource. Changing this forces a new resource to be created."
  default     = ""
}

variable "active_directory_domain_service_location" {
  description = "(Required) The Azure location where the Domain Service exists. Changing this forces a new resource to be created."
  default     = null
}

variable "active_directory_domain_service_resource_group_name" {
  description = "(Required) The name of the Resource Group in which the Domain Service should exist. Changing this forces a new resource to be created."
  default     = null
}

variable "active_directory_domain_service_sku" {
  description = "(Required) The SKU to use when provisioning the Domain Service resource. One of Standard, Enterprise or Premium"
  default     = null
}

variable "active_directory_domain_service_domain_name" {
  description = "(Required) The Active Directory domain to use. See official documentation for constraints and recommendations."
  default     = null
}

variable "active_directory_domain_service_filtered_sync_enabled" {
  description = "Whether to enable group-based filtered sync (also called scoped synchronisation). Defaults to false"
  default     = null
}

variable "active_directory_domain_service_secure_ldap" {
  description = "(Optional) A secure_ldap block"
  default     = []
}

variable "active_directory_domain_service_initial_replica_set" {
  description = "(Required) An initial_replica_set block. The initial replica set inherits the same location as the Domain Service resource."
  default     = []
}

variable "user_assigned_identity_notifications" {
  description = "(Optional) A notifications block"
  default     = []
}

variable "user_assigned_identity_security" {
  description = "(Optional) A security block"
  default     = {}
}

variable "user_assigned_identity_timeouts" {
  description = "Set timeouts for user assigned identity"
  default     = {}
}

#-----------------------------------------------------------
# Azure active directory domain service replica set
#-----------------------------------------------------------
variable "enable_active_directory_domain_service_replica_set" {
  description = "Enable active directory domain service replica set usage"
  default     = false
}

variable "active_directory_domain_service_replica_set_domain_service_id" {
  description = "The ID of the Domain Service for which to create this Replica Set. Changing this forces a new resource to be created."
  default     = ""
}

variable "active_directory_domain_service_replica_set_location" {
  description = "(Required) The Azure location where this Replica Set should exist. Changing this forces a new resource to be created."
  default     = null
}

variable "active_directory_domain_service_replica_set_subnet_id" {
  description = "(Required) The ID of the subnet in which to place this Replica Set."
  default     = null
}

variable "active_directory_domain_service_replica_set_timeouts" {
  description = "Set timeouts active directory domain service replica set"
  default     = {}
}

resource "awscc_ec2_subnet_route_table_association" "this" {
  route_table_id = awscc_ec2_route_table.this.id
  subnet_id      = awscc_ec2_subnet.this.id
}

resource "awscc_ec2_vpc" "this" {
  cidr_block = "10.0.0.0/16"
  tags = [{
    key   = "Managed By"
    value = "AWSCC"
  }]
}

resource "awscc_ec2_route_table" "this" {
  vpc_id = awscc_ec2_vpc.this.id
  tags = [{
    key   = "Managed By"
    value = "AWSCC"
  }]
}

resource "awscc_ec2_subnet" "this" {
  vpc_id            = awscc_ec2_vpc.this.id
  cidr_block        = "10.0.101.0/24"
  availability_zone = "us-east-1a"
  tags = [{
    key   = "Managed By"
    value = "AWSCC"
  }]
}

resource "dnacenter_network_create" "example" {
  provider = dnacenter
  site_id  = "string"
  parameters {

    settings {

      client_and_endpoint_aaa {

        ip_address    = "string"
        network       = "string"
        protocol      = "string"
        servers       = "string"
        shared_secret = "string"
      }
      dhcp_server = ["string"]
      dns_server {

        domain_name          = "string"
        primary_ip_address   = "string"
        secondary_ip_address = "string"
      }
      message_of_theday {

        banner_message         = "string"
        retain_existing_banner = "string"
      }
      netflowcollector {

        ip_address = "string"
        port       = 9090
      }
      network_aaa {

        ip_address    = "string"
        network       = "string"
        protocol      = "string"
        servers       = "string"
        shared_secret = "string"
      }
      ntp_server = ["string"]
      snmp_server {

        configure_dnac_ip = "false"
        ip_addresses      = ["string"]
      }
